/**
 * Migration: Add gamification + content depth tables to existing database.
 * Safe to run multiple times — uses IF NOT EXISTS.
 */
const Database = require('better-sqlite3');
const path = require('path');

const dbPath = path.join(__dirname, 'local.db');
const db = new Database(dbPath);
db.pragma('journal_mode = WAL');

const migrations = [
  // ─── Gamification: XP Tracking ───
  `CREATE TABLE IF NOT EXISTS "user_xp" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "user_id" text NOT NULL UNIQUE REFERENCES "user"("id") ON DELETE CASCADE,
    "total_xp" integer DEFAULT 0 NOT NULL,
    "level" integer DEFAULT 1 NOT NULL,
    "current_streak" integer DEFAULT 0 NOT NULL,
    "longest_streak" integer DEFAULT 0 NOT NULL,
    "last_study_date" text,
    "updated_at" integer NOT NULL DEFAULT (cast(unixepoch() as integer))
  )`,
  `CREATE INDEX IF NOT EXISTS "user_xp_userId_idx" ON "user_xp"("user_id")`,

  // ─── Gamification: Achievements ───
  `CREATE TABLE IF NOT EXISTS "user_achievements" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "user_id" text NOT NULL REFERENCES "user"("id") ON DELETE CASCADE,
    "achievement_key" text NOT NULL,
    "unlocked_at" integer NOT NULL DEFAULT (cast(unixepoch() as integer))
  )`,
  `CREATE INDEX IF NOT EXISTS "achievements_userId_idx" ON "user_achievements"("user_id")`,
  `CREATE INDEX IF NOT EXISTS "achievements_key_idx" ON "user_achievements"("user_id", "achievement_key")`,

  // ─── Gamification: Daily Challenges ───
  `CREATE TABLE IF NOT EXISTS "daily_challenges" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "user_id" text NOT NULL REFERENCES "user"("id") ON DELETE CASCADE,
    "date" text NOT NULL,
    "challenge_type" text NOT NULL,
    "target_value" integer NOT NULL,
    "current_value" integer DEFAULT 0 NOT NULL,
    "completed" integer DEFAULT 0 NOT NULL,
    "xp_reward" integer DEFAULT 50 NOT NULL,
    "created_at" integer NOT NULL DEFAULT (cast(unixepoch() as integer))
  )`,
  `CREATE INDEX IF NOT EXISTS "challenges_userId_date_idx" ON "daily_challenges"("user_id", "date")`,

  // ─── Content: Compound Words ───
  `CREATE TABLE IF NOT EXISTS "compound_words" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "character" text NOT NULL,
    "word" text NOT NULL,
    "pinyin" text NOT NULL,
    "meaning" text NOT NULL,
    "hsk_level" integer
  )`,
  `CREATE INDEX IF NOT EXISTS "compound_words_char_idx" ON "compound_words"("character")`,

  // ─── Ensure missing tables from earlier migrations ───
  `CREATE TABLE IF NOT EXISTS "study_sessions" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "user_id" text NOT NULL REFERENCES "user"("id") ON DELETE CASCADE,
    "date" text NOT NULL,
    "cards_reviewed" integer DEFAULT 0 NOT NULL,
    "cards_correct" integer DEFAULT 0 NOT NULL,
    "study_minutes" integer DEFAULT 0 NOT NULL,
    "created_at" integer NOT NULL DEFAULT (cast(unixepoch() as integer))
  )`,
  `CREATE INDEX IF NOT EXISTS "sessions_userId_idx" ON "study_sessions"("user_id")`,
  `CREATE INDEX IF NOT EXISTS "sessions_date_idx" ON "study_sessions"("user_id", "date")`,

  `CREATE TABLE IF NOT EXISTS "review_logs" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "user_id" text NOT NULL REFERENCES "user"("id") ON DELETE CASCADE,
    "flashcard_id" integer NOT NULL REFERENCES "flashcards"("id") ON DELETE CASCADE,
    "quality" integer NOT NULL,
    "response_time_ms" integer,
    "created_at" integer NOT NULL DEFAULT (cast(unixepoch() as integer))
  )`,
  `CREATE INDEX IF NOT EXISTS "review_logs_userId_idx" ON "review_logs"("user_id")`,
  `CREATE INDEX IF NOT EXISTS "review_logs_createdAt_idx" ON "review_logs"("user_id", "created_at")`,
  `CREATE INDEX IF NOT EXISTS "review_logs_flashcardId_idx" ON "review_logs"("flashcard_id")`,

  `CREATE TABLE IF NOT EXISTS "character_sentences" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "character" text NOT NULL,
    "sentence" text NOT NULL,
    "pinyin" text NOT NULL,
    "translation" text NOT NULL,
    "hsk_level" integer
  )`,
  `CREATE INDEX IF NOT EXISTS "sentences_character_idx" ON "character_sentences"("character")`,

  `CREATE TABLE IF NOT EXISTS "character_radicals" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "character" text NOT NULL UNIQUE,
    "radicals" text NOT NULL,
    "decomposition" text,
    "etymology" text
  )`,

  `CREATE TABLE IF NOT EXISTS "notifications" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "user_id" text NOT NULL REFERENCES "user"("id") ON DELETE CASCADE,
    "title" text NOT NULL,
    "message" text NOT NULL,
    "type" text NOT NULL,
    "read" integer DEFAULT 0 NOT NULL,
    "data" text,
    "created_at" integer NOT NULL DEFAULT (cast(unixepoch() as integer))
  )`,
  `CREATE INDEX IF NOT EXISTS "notifications_userId_idx" ON "notifications"("user_id")`,
  `CREATE INDEX IF NOT EXISTS "notifications_read_idx" ON "notifications"("user_id", "read")`,

  // ─── Indexes for existing tables that may be missing ───
  `CREATE INDEX IF NOT EXISTS "flashcards_deckId_idx" ON "flashcards"("deck_id")`,
  `CREATE INDEX IF NOT EXISTS "flashcards_hskLevel_idx" ON "flashcards"("hsk_level")`,
  `CREATE INDEX IF NOT EXISTS "flashcards_character_idx" ON "flashcards"("character")`,
  `CREATE INDEX IF NOT EXISTS "progress_userId_idx" ON "user_progress"("user_id")`,
  `CREATE INDEX IF NOT EXISTS "progress_dueDate_idx" ON "user_progress"("user_id", "due_date")`,
  `CREATE INDEX IF NOT EXISTS "progress_flashcardId_idx" ON "user_progress"("flashcard_id")`,
];

console.log('🔄 Running migrations...');
let applied = 0;

for (const sql of migrations) {
  try {
    db.exec(sql);
    applied++;
  } catch (err) {
    // Ignore "already exists" errors
    if (!err.message.includes('already exists')) {
      console.warn(`⚠️  ${err.message}`);
    }
  }
}

console.log(`✅ Applied ${applied}/${migrations.length} migration statements`);

// ─── Seed compound words if empty ───
const count = db.prepare('SELECT COUNT(*) as c FROM compound_words').get();
if (count.c === 0) {
  console.log('📝 Seeding compound words...');
  const compounds = [
    // 学 (xué) - Study
    ['学', '学生', 'xuéshēng', 'student', 1],
    ['学', '学校', 'xuéxiào', 'school', 1],
    ['学', '学习', 'xuéxí', 'to study/learn', 1],
    ['学', '大学', 'dàxué', 'university', 2],
    ['学', '同学', 'tóngxué', 'classmate', 1],
    // 人 (rén) - Person
    ['人', '人们', 'rénmen', 'people', 2],
    ['人', '大人', 'dàrén', 'adult', 2],
    ['人', '工人', 'gōngrén', 'worker', 3],
    ['人', '个人', 'gèrén', 'individual', 3],
    // 大 (dà) - Big
    ['大', '大家', 'dàjiā', 'everyone', 1],
    ['大', '大学', 'dàxué', 'university', 2],
    ['大', '伟大', 'wěidà', 'great/mighty', 4],
    // 中 (zhōng) - Middle
    ['中', '中国', 'zhōngguó', 'China', 1],
    ['中', '中文', 'zhōngwén', 'Chinese language', 1],
    ['中', '中间', 'zhōngjiān', 'middle/between', 2],
    ['中', '中心', 'zhōngxīn', 'center', 3],
    // 好 (hǎo) - Good
    ['好', '好吃', 'hǎochī', 'delicious', 1],
    ['好', '好看', 'hǎokàn', 'good-looking', 1],
    ['好', '好人', 'hǎorén', 'good person', 1],
    // 书 (shū) - Book
    ['书', '书法', 'shūfǎ', 'calligraphy', 3],
    ['书', '书包', 'shūbāo', 'schoolbag', 2],
    ['书', '读书', 'dúshū', 'to read/study', 2],
    // 水 (shuǐ) - Water
    ['水', '水果', 'shuǐguǒ', 'fruit', 1],
    ['水', '喝水', 'hēshuǐ', 'to drink water', 1],
    ['水', '水平', 'shuǐpíng', 'level/standard', 3],
    // 心 (xīn) - Heart
    ['心', '开心', 'kāixīn', 'happy', 2],
    ['心', '小心', 'xiǎoxīn', 'be careful', 2],
    ['心', '中心', 'zhōngxīn', 'center', 3],
    ['心', '心情', 'xīnqíng', 'mood', 3],
    // 爱 (ài) - Love
    ['爱', '爱好', 'àihào', 'hobby', 2],
    ['爱', '可爱', 'kěài', 'cute/lovely', 2],
    ['爱', '爱情', 'àiqíng', 'romantic love', 4],
    // 天 (tiān) - Day/Sky
    ['天', '今天', 'jīntiān', 'today', 1],
    ['天', '明天', 'míngtiān', 'tomorrow', 1],
    ['天', '天气', 'tiānqì', 'weather', 1],
    ['天', '每天', 'měitiān', 'every day', 1],
    // 日 (rì) - Sun/Day
    ['日', '日本', 'rìběn', 'Japan', 2],
    ['日', '生日', 'shēngrì', 'birthday', 1],
    ['日', '日记', 'rìjì', 'diary', 3],
    // 月 (yuè) - Moon/Month
    ['月', '月亮', 'yuèliàng', 'moon', 2],
    ['月', '一月', 'yīyuè', 'January', 1],
    // 火 (huǒ) - Fire
    ['火', '火车', 'huǒchē', 'train', 1],
    ['火', '大火', 'dàhuǒ', 'big fire', 2],
    // 山 (shān) - Mountain
    ['山', '山水', 'shānshuǐ', 'landscape', 3],
    ['山', '上山', 'shàngshān', 'go up the mountain', 2],
    // 龙 (lóng) - Dragon
    ['龙', '恐龙', 'kǒnglóng', 'dinosaur', 4],
    ['龙', '龙舟', 'lóngzhōu', 'dragon boat', 4],
    // 永 (yǒng) - Eternity
    ['永', '永远', 'yǒngyuǎn', 'forever', 3],
    ['永', '永恒', 'yǒnghéng', 'eternal', 5],
  ];

  const insert = db.prepare('INSERT INTO compound_words (character, word, pinyin, meaning, hsk_level) VALUES (?, ?, ?, ?, ?)');
  const batch = db.transaction((items) => {
    for (const item of items) insert.run(...item);
  });
  batch(compounds);
  console.log(`  → Inserted ${compounds.length} compound words`);
}

console.log('✅ Migration complete!');
db.close();

const Database = require('better-sqlite3');
const path = require('path');

const dbPath = path.join(__dirname, 'local.db');
const db = new Database(dbPath);

console.log('Seeding test data for the user...');

const user = db.prepare('SELECT id FROM user LIMIT 1').get();
if (!user) {
  console.log('No user found! Please register/login first.');
  process.exit();
}

const userId = user.id;

// Create Decks
const insertDeck = db.prepare('INSERT INTO decks (user_id, title, description, created_at) VALUES (?, ?, ?, ?) RETURNING id');
const hsk1Deck = insertDeck.get(userId, 'HSK 1 Vocabulary', 'Basic Chinese characters for beginners', Date.now());
const radicalsDeck = insertDeck.get(userId, 'Common Radicals', 'Essential building blocks of characters', Date.now());

const insertCard = db.prepare('INSERT INTO flashcards (deck_id, character, pinyin, meaning, strokes, hsk_level, created_at) VALUES (?, ?, ?, ?, ?, ?, ?) RETURNING id');

const cards = [
  // HSK 1
  [hsk1Deck.id, '学', 'xué', 'to study; to learn', 8, 1],
  [hsk1Deck.id, '人', 'rén', 'person; people', 2, 1],
  [hsk1Deck.id, '大', 'dà', 'big; large', 3, 1],
  [hsk1Deck.id, '中', 'zhōng', 'middle; center', 4, 1],
  [hsk1Deck.id, '好', 'hǎo', 'good; well', 6, 1],
  [hsk1Deck.id, '天', 'tiān', 'sky; day', 4, 1],

  // Radicals
  [radicalsDeck.id, '水', 'shuǐ', 'water (radical: 氵)', 4, 1],
  [radicalsDeck.id, '心', 'xīn', 'heart (radical: 忄)', 4, 1],
  [radicalsDeck.id, '火', 'huǒ', 'fire (radical: 灬)', 4, 1],
  [radicalsDeck.id, '日', 'rì', 'sun; day', 4, 1],
  [radicalsDeck.id, '月', 'yuè', 'moon; month', 4, 1]
];

const insertCardStmt = db.transaction((cards) => {
  for (const card of cards) {
    insertCard.get(...card, Date.now());
  }
});

insertCardStmt(cards);

console.log('✅ Test decks and flashcards have been seeded!');
db.close();

const Database = require('better-sqlite3');
const path = require('path');
const fs = require('fs');

const dbPath = path.join(__dirname, 'local.db');

// Delete existing DB
[dbPath, dbPath + '-wal', dbPath + '-shm'].forEach(f => {
  try { fs.unlinkSync(f); } catch {}
});

const db = new Database(dbPath);
db.pragma('journal_mode = WAL');

db.exec(`
  CREATE TABLE "user" (
    "id" text PRIMARY KEY NOT NULL,
    "name" text NOT NULL,
    "email" text NOT NULL UNIQUE,
    "email_verified" integer DEFAULT 0 NOT NULL,
    "image" text,
    "created_at" integer DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)) NOT NULL,
    "updated_at" integer DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)) NOT NULL
  );

  CREATE TABLE "session" (
    "id" text PRIMARY KEY NOT NULL,
    "expires_at" integer NOT NULL,
    "token" text NOT NULL UNIQUE,
    "created_at" integer DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)) NOT NULL,
    "updated_at" integer DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)) NOT NULL,
    "ip_address" text,
    "user_agent" text,
    "user_id" text NOT NULL REFERENCES "user"("id") ON DELETE CASCADE
  );
  CREATE INDEX "session_userId_idx" ON "session"("user_id");

  CREATE TABLE "account" (
    "id" text PRIMARY KEY NOT NULL,
    "account_id" text NOT NULL,
    "provider_id" text NOT NULL,
    "user_id" text NOT NULL REFERENCES "user"("id") ON DELETE CASCADE,
    "access_token" text,
    "refresh_token" text,
    "id_token" text,
    "access_token_expires_at" integer,
    "refresh_token_expires_at" integer,
    "scope" text,
    "password" text,
    "created_at" integer DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)) NOT NULL,
    "updated_at" integer DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)) NOT NULL
  );
  CREATE INDEX "account_userId_idx" ON "account"("user_id");

  CREATE TABLE "verification" (
    "id" text PRIMARY KEY NOT NULL,
    "identifier" text NOT NULL,
    "value" text NOT NULL,
    "expires_at" integer NOT NULL,
    "created_at" integer DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)) NOT NULL,
    "updated_at" integer DEFAULT (cast(unixepoch('subsecond') * 1000 as integer)) NOT NULL
  );
  CREATE INDEX "verification_identifier_idx" ON "verification"("identifier");

  CREATE TABLE "decks" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "user_id" text NOT NULL REFERENCES "user"("id"),
    "title" text NOT NULL,
    "description" text,
    "created_at" integer NOT NULL
  );

  CREATE TABLE "flashcards" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "deck_id" integer NOT NULL REFERENCES "decks"("id"),
    "character" text NOT NULL,
    "pinyin" text NOT NULL,
    "meaning" text NOT NULL,
    "strokes" integer,
    "hsk_level" integer,
    "created_at" integer NOT NULL
  );

  CREATE TABLE "user_progress" (
    "id" integer PRIMARY KEY AUTOINCREMENT,
    "user_id" text NOT NULL REFERENCES "user"("id"),
    "flashcard_id" integer NOT NULL REFERENCES "flashcards"("id"),
    "interval" integer DEFAULT 0 NOT NULL,
    "repetition" integer DEFAULT 0 NOT NULL,
    "efactor" integer DEFAULT 2500 NOT NULL,
    "due_date" integer NOT NULL
  );
`);

console.log('✅ Database recreated with snake_case columns at:', dbPath);
db.close();

'use client';

import { trpc } from '@/trpc/client';
import { usePageTitle } from '@/hooks/usePageTitle';
import { ForecastChart } from '@/components/ForecastChart';
import { MasteryMap } from '@/components/MasteryMap';
import { PageTransition, StaggerContainer, StaggerItem } from '@/components/Animations';
import Link from 'next/link';

const QUALITY_LABELS: Record<number, { label: string; color: string }> = {
  0: { label: 'Blackout', color: 'text-error' },
  1: { label: 'Again', color: 'text-error' },
  2: { label: 'Hard', color: 'text-on-surface-variant' },
  3: { label: 'Hard', color: 'text-on-surface-variant' },
  4: { label: 'Good', color: 'text-primary' },
  5: { label: 'Easy', color: 'text-secondary' },
};

function HeatmapGrid({ data }: { data: { date: string; cardsReviewed: number }[] }) {
  // Build 365-day grid ending today
  const today = new Date();
  const cells: { date: string; count: number }[] = [];
  const dataMap = new Map(data.map(d => [d.date, d.cardsReviewed]));

  for (let i = 364; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);
    cells.push({ date: dateStr, count: dataMap.get(dateStr) ?? 0 });
  }

  const maxCount = Math.max(1, ...cells.map(c => c.count));

  // Group into weeks (columns of 7)
  const weeks: { date: string; count: number }[][] = [];
  for (let i = 0; i < cells.length; i += 7) {
    weeks.push(cells.slice(i, i + 7));
  }

  const getColor = (count: number) => {
    if (count === 0) return 'bg-surface-container-high';
    const intensity = count / maxCount;
    if (intensity > 0.75) return 'bg-primary';
    if (intensity > 0.5) return 'bg-primary/70';
    if (intensity > 0.25) return 'bg-primary/40';
    return 'bg-primary/20';
  };

  return (
    <div className="overflow-x-auto">
      <div className="flex gap-[3px] min-w-[700px]">
        {weeks.map((week, wi) => (
          <div key={wi} className="flex flex-col gap-[3px]">
            {week.map((cell) => (
              <div
                key={cell.date}
                className={`w-3 h-3 rounded-sm ${getColor(cell.count)} transition-colors`}
                title={`${cell.date}: ${cell.count} reviews`}
              />
            ))}
          </div>
        ))}
      </div>
      <div className="flex items-center gap-2 mt-3 text-[10px] text-on-surface-variant">
        <span>Less</span>
        <div className="w-3 h-3 rounded-sm bg-surface-container-high" />
        <div className="w-3 h-3 rounded-sm bg-primary/20" />
        <div className="w-3 h-3 rounded-sm bg-primary/40" />
        <div className="w-3 h-3 rounded-sm bg-primary/70" />
        <div className="w-3 h-3 rounded-sm bg-primary" />
        <span>More</span>
      </div>
    </div>
  );
}

export default function AnalyticsPage() {
  usePageTitle('Analytics');
  const { data: heatmap, isLoading: heatmapLoading } = trpc.getHeatmapData.useQuery();
  const { data: weakest, isLoading: weakestLoading } = trpc.getWeakestCharacters.useQuery();
  const { data: sessions, isLoading: sessionsLoading } = trpc.getSessionHistory.useQuery();
  const { data: recentReviews, isLoading: reviewsLoading } = trpc.getRecentReviews.useQuery();

  const totalSessions = sessions?.length ?? 0;
  const totalReviewed = sessions?.reduce((sum, s) => sum + s.cardsReviewed, 0) ?? 0;
  const totalCorrect = sessions?.reduce((sum, s) => sum + s.cardsCorrect, 0) ?? 0;
  const overallAccuracy = totalReviewed > 0 ? Math.round((totalCorrect / totalReviewed) * 100) : 0;

  // Accuracy trend (last 7 vs previous 7)
  const recent7 = sessions?.slice(0, 7) ?? [];
  const prev7 = sessions?.slice(7, 14) ?? [];
  const recent7Acc = recent7.reduce((s, r) => s + r.cardsCorrect, 0) / Math.max(1, recent7.reduce((s, r) => s + r.cardsReviewed, 0)) * 100;
  const prev7Acc = prev7.reduce((s, r) => s + r.cardsCorrect, 0) / Math.max(1, prev7.reduce((s, r) => s + r.cardsReviewed, 0)) * 100;
  const accTrend = recent7Acc - prev7Acc;

  return (
    <div className="p-4 sm:p-6 md:p-8 max-w-7xl mx-auto space-y-6 md:space-y-8 pb-24 md:pb-8">
      {/* Header */}
      <section className="flex flex-col sm:flex-row justify-between items-start sm:items-end gap-4 pb-2">
        <div className="space-y-1">
          <span className="text-[0.6875rem] font-bold tracking-[0.15em] text-primary uppercase">Learning Insights</span>
          <h2 className="text-2xl sm:text-3xl font-extrabold text-on-surface font-[family-name:var(--font-jakarta)] leading-tight">Analytics Dashboard</h2>
        </div>
        <Link href="/" className="text-sm font-bold text-primary hover:underline flex items-center gap-1">
          <span className="material-symbols-outlined text-[16px]">arrow_back</span>
          Back to Dashboard
        </Link>
      </section>

      {/* Summary Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {[
          { label: 'Total Sessions', value: totalSessions, icon: 'calendar_today' },
          { label: 'Cards Reviewed', value: totalReviewed.toLocaleString(), icon: 'style' },
          { label: 'Overall Accuracy', value: `${overallAccuracy}%`, icon: 'target' },
          { label: 'Accuracy Trend', value: `${accTrend >= 0 ? '+' : ''}${accTrend.toFixed(1)}%`, icon: accTrend >= 0 ? 'trending_up' : 'trending_down' },
        ].map((stat) => (
          <div key={stat.label} className="bg-surface-container-low p-4 sm:p-5 rounded-2xl">
            <div className="flex items-center gap-2 mb-2">
              <span className="material-symbols-outlined text-primary text-[18px]">{stat.icon}</span>
              <p className="text-[10px] font-bold text-outline uppercase tracking-widest">{stat.label}</p>
            </div>
            {sessionsLoading ? (
              <div className="h-6 w-16 bg-surface-container-high rounded animate-pulse" />
            ) : (
              <p className="text-xl sm:text-2xl font-black text-on-surface">{stat.value}</p>
            )}
          </div>
        ))}
      </div>

      {/* Study Heatmap */}
      <div className="bg-surface-container-low rounded-2xl p-6 sm:p-8">
        <h3 className="font-[family-name:var(--font-jakarta)] font-bold text-lg text-on-surface mb-6">Study Activity</h3>
        {heatmapLoading ? (
          <div className="h-24 bg-surface-container-high rounded animate-pulse" />
        ) : (
          <HeatmapGrid data={heatmap ?? []} />
        )}
      </div>

      {/* Spaced Repetition Forecast */}
      <ForecastChart />

      {/* Character Mastery Map */}
      <MasteryMap />

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 sm:gap-6">
        {/* Weakest Characters */}
        <div className="bg-surface-container-low rounded-2xl p-6 sm:p-8">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-[family-name:var(--font-jakarta)] font-bold text-lg text-on-surface">Weakest Characters</h3>
            <span className="text-[10px] font-bold text-outline uppercase tracking-widest">Lowest E-Factor</span>
          </div>
          {weakestLoading ? (
            <div className="space-y-3">
              {Array.from({ length: 5 }).map((_, i) => (
                <div key={i} className="h-12 bg-surface-container-high rounded-xl animate-pulse" />
              ))}
            </div>
          ) : weakest?.weakest && weakest.weakest.length > 0 ? (
            <div className="space-y-3">
              {weakest.weakest.map((w, i) => (
                <div key={w.flashcardId} className="flex items-center gap-4 p-3 bg-surface-container-lowest rounded-xl border border-outline-variant/10">
                  <span className="text-xs font-bold text-outline w-5">{i + 1}</span>
                  <div className="w-10 h-10 bg-error/10 rounded-lg flex items-center justify-center flex-shrink-0">
                    <span className="chinese-char text-lg font-bold text-on-surface">{w.character}</span>
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-bold text-on-surface text-sm">{w.pinyin}</p>
                    <p className="text-xs text-on-surface-variant truncate">{w.meaning}</p>
                  </div>
                  <div className="text-right flex-shrink-0">
                    <p className="text-xs font-bold text-error">{(w.efactor / 1000).toFixed(2)}</p>
                    <p className="text-[9px] text-outline">e-factor</p>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-8">
              <span className="material-symbols-outlined text-4xl text-outline/40">psychology</span>
              <p className="text-sm text-on-surface-variant mt-2">No review data yet. Start practicing!</p>
            </div>
          )}
        </div>

        {/* Session History */}
        <div className="bg-surface-container-low rounded-2xl p-6 sm:p-8">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-[family-name:var(--font-jakarta)] font-bold text-lg text-on-surface">Session History</h3>
            <span className="text-[10px] font-bold text-outline uppercase tracking-widest">Last 30 days</span>
          </div>
          {sessionsLoading ? (
            <div className="space-y-3">
              {Array.from({ length: 5 }).map((_, i) => (
                <div key={i} className="h-12 bg-surface-container-high rounded-xl animate-pulse" />
              ))}
            </div>
          ) : sessions && sessions.length > 0 ? (
            <div className="space-y-2">
              {sessions.slice(0, 10).map((s, i) => {
                const acc = s.cardsReviewed > 0 ? Math.round((s.cardsCorrect / s.cardsReviewed) * 100) : 0;
                return (
                  <div key={i} className="flex items-center justify-between p-3 bg-surface-container-lowest rounded-xl border border-outline-variant/10">
                    <div className="flex items-center gap-3">
                      <span className="material-symbols-outlined text-primary text-[18px]">calendar_today</span>
                      <span className="text-sm font-medium text-on-surface">{s.date}</span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="text-xs text-on-surface-variant">{s.cardsReviewed} cards</span>
                      <div className="w-16 h-1.5 bg-surface-container-high rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${acc >= 80 ? 'bg-primary' : acc >= 50 ? 'bg-secondary' : 'bg-error'}`} style={{ width: `${acc}%` }} />
                      </div>
                      <span className={`text-xs font-bold ${acc >= 80 ? 'text-primary' : acc >= 50 ? 'text-secondary' : 'text-error'}`}>{acc}%</span>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            <div className="text-center py-8">
              <span className="material-symbols-outlined text-4xl text-outline/40">history</span>
              <p className="text-sm text-on-surface-variant mt-2">No sessions recorded yet.</p>
            </div>
          )}
        </div>
      </div>

      {/* Recent Review Log */}
      <div className="bg-surface-container-low rounded-2xl p-6 sm:p-8">
        <h3 className="font-[family-name:var(--font-jakarta)] font-bold text-lg text-on-surface mb-6">Recent Reviews</h3>
        {reviewsLoading ? (
          <div className="h-24 bg-surface-container-high rounded animate-pulse" />
        ) : recentReviews && recentReviews.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
            {recentReviews.slice(0, 12).map((r, i) => {
              const q = QUALITY_LABELS[r.quality] ?? QUALITY_LABELS[3];
              return (
                <div key={i} className="flex items-center gap-3 p-3 bg-surface-container-lowest rounded-xl border border-outline-variant/10">
                  <div className="w-10 h-10 bg-surface-container-low rounded-lg flex items-center justify-center flex-shrink-0">
                    <span className="chinese-char text-lg font-bold text-on-surface">{r.character}</span>
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="font-bold text-on-surface text-sm truncate">{r.pinyin}</p>
                    <p className="text-xs text-on-surface-variant truncate">{r.meaning}</p>
                  </div>
                  <span className={`text-xs font-bold ${q.color}`}>{q.label}</span>
                </div>
              );
            })}
          </div>
        ) : (
          <div className="text-center py-8">
            <span className="material-symbols-outlined text-4xl text-outline/40">reviews</span>
            <p className="text-sm text-on-surface-variant mt-2">No reviews recorded yet. Practice to see your history!</p>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { 
  createColumnHelper, 
  flexRender, 
  getCoreRowModel, 
  useReactTable 
} from '@tanstack/react-table';
import { ChevronRight, Save, Upload } from 'lucide-react';
import Link from 'next/link';

const CardSchema = z.object({
  character: z.string().min(1, "Character needed"),
  pinyin: z.string().min(1, "Pinyin needed"),
  meaning: z.string().min(1, "Meaning needed"),
});

const DeckSchema = z.object({
  title: z.string().min(2, "Title must be at least 2 characters"),
  description: z.string().optional(),
});

type CardData = z.infer<typeof CardSchema>;
type DeckDetails = z.infer<typeof DeckSchema>;

export default function NewDeckPage() {
  const [cards, setCards] = useState<CardData[]>([]);
  const [pasteData, setPasteData] = useState("");

  const { register, handleSubmit, formState: { errors } } = useForm<DeckDetails>({
    resolver: zodResolver(DeckSchema),
  });

  const handleParse = () => {
    // Basic CSV/TSV parser: "好 hǎo good" or "好,hǎo,good"
    const lines = pasteData.split('\n');
    const parsed: CardData[] = [];
    lines.forEach(line => {
      if (!line.trim()) return;
      const parts = line.split(/[\t,]/).map(s => s.trim());
      if (parts.length >= 3) {
        parsed.push({
          character: parts[0],
          pinyin: parts[1],
          meaning: parts.slice(2).join(' '), // In case meaning had commas
        });
      }
    });
    setCards(parsed);
  };

  const onSubmit = (data: DeckDetails) => {
    console.log("Saving deck:", data, "with cards:", cards);
    // Ideally mutation.mutate({ ...data, cards })
    alert("Deck Saved successfully! Redirecting...");
  };

  const columnHelper = createColumnHelper<CardData>();
  const columns = [
    columnHelper.accessor('character', { header: 'Character', cell: info => info.getValue() }),
    columnHelper.accessor('pinyin', { header: 'Pinyin', cell: info => info.getValue() }),
    columnHelper.accessor('meaning', { header: 'Meaning', cell: info => info.getValue() }),
  ];

  const table = useReactTable({
    data: cards,
    columns,
    getCoreRowModel: getCoreRowModel(),
  });

  return (
    <div className="max-w-5xl mx-auto py-6">
       <div className="flex items-center gap-2 text-sm text-slate-500 mb-6">
          <Link href="/decks" className="hover:text-slate-800">Decks</Link>
          <ChevronRight size={14} />
          <span className="text-slate-800 font-medium">Import new deck</span>
       </div>

       <div className="flex justify-between items-end mb-8">
          <div>
             <h1 className="text-3xl font-bold text-slate-800">Import Flashcards</h1>
             <p className="text-slate-500 mt-2">Paste your words list from Excel, Pleco, or Quizlet.</p>
          </div>
       </div>

       <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1 space-y-6">
            <form id="deckForm" onSubmit={handleSubmit(onSubmit)} className="space-y-4 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Deck Title</label>
                  <input {...register('title')} className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="e.g. HSK 1 Vocabulary" />
                  {errors.title && <p className="text-red-500 text-sm mt-1">{errors.title.message}</p>}
               </div>
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Description (Optional)</label>
                  <textarea {...register('description')} className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="Describe the focus of this deck..." rows={3} />
               </div>
            </form>

             <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
               <h3 className="font-medium text-slate-800 mb-4 flex items-center gap-2">
                 <Upload size={18} className="text-blue-600" /> Bulk Import
               </h3>
               <p className="text-xs text-slate-500 mb-3">Paste exactly 3 columns: Character, Pinyin, Meaning separated by Tab or Comma.</p>
               <textarea 
                  value={pasteData}
                  onChange={(e) => setPasteData(e.target.value)}
                  className="w-full border border-slate-300 rounded-lg p-2.5 mb-3 focus:ring-2 focus:ring-blue-500 outline-none text-sm font-mono" 
                  rows={6} 
                  placeholder="好   hǎo   good&#10;人   rén   person"
               />
               <button type="button" onClick={handleParse} className="w-full py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition text-sm font-medium">
                 Parse Cards
               </button>
             </div>
          </div>

          <div className="lg:col-span-2">
             <div className="bg-white border text-sm border-slate-200 rounded-2xl shadow-sm overflow-hidden flex flex-col h-full min-h-[500px]">
                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
                   <h3 className="font-semibold text-slate-800">Preview ({cards.length} cards)</h3>
                   <button 
                      form="deckForm"
                      type="submit"
                      disabled={cards.length === 0} 
                      className="px-4 py-2 bg-blue-600 disabled:opacity-50 text-white rounded-lg shadow-sm font-medium hover:bg-blue-700 transition flex items-center gap-2 text-sm"
                   >
                     <Save size={16} /> Save Deck
                   </button>
                </div>
                
                {cards.length === 0 ? (
                  <div className="flex-1 flex items-center justify-center text-slate-400 p-8 text-center flex-col gap-4">
                     <p>Paste data and click "Parse Cards" to preview your import.</p>
                  </div>
                ) : (
                  <div className="overflow-x-auto">
                     <table className="w-full text-left border-collapse">
                        <thead>
                           {table.getHeaderGroups().map(headerGroup => (
                              <tr key={headerGroup.id} className="border-b border-slate-200">
                                 {headerGroup.headers.map(header => (
                                    <th key={header.id} className="p-4 font-semibold text-slate-600 bg-slate-50">
                                       {flexRender(header.column.columnDef.header, header.getContext())}
                                    </th>
                                 ))}
                              </tr>
                           ))}
                        </thead>
                        <tbody>
                           {table.getRowModel().rows.map(row => (
                              <tr key={row.id} className="border-b border-slate-100 hover:bg-slate-50/50">
                                 {row.getVisibleCells().map(cell => (
                                    <td key={cell.id} className="p-4 text-slate-700">
                                       {flexRender(cell.column.columnDef.cell, cell.getContext())}
                                    </td>
                                 ))}
                              </tr>
                           ))}
                        </tbody>
                     </table>
                  </div>
                )}
             </div>
          </div>
       </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useSearchParams } from 'next/navigation';
import { trpc } from '@/trpc/client';
import { SpeakButton } from '@/components/SpeakButton';
import { usePageTitle } from '@/hooks/usePageTitle';

const HISTORY_KEY = 'dc-search-history';

interface HistoryEntry {
  char: string;
  pinyin: string;
  meaning: string;
  time: string;
}

function loadHistory(): HistoryEntry[] {
  if (typeof window === 'undefined') return [];
  try {
    const raw = localStorage.getItem(HISTORY_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
}

export default function DictionaryPage() {
  usePageTitle('Dictionary');
  const searchParams = useSearchParams();
  const initialQuery = searchParams.get('q') ?? '';
  const [query, setQuery] = useState(initialQuery);
  const [hskFilter, setHskFilter] = useState<number | undefined>(undefined);
  const [searchHistory, setSearchHistory] = useState<HistoryEntry[]>([]);
  const [addingToStudy, setAddingToStudy] = useState<string | null>(null);

  // Sync URL query param
  useEffect(() => {
    const q = searchParams.get('q');
    if (q && q !== query) setQuery(q);
  }, [searchParams]);

  // Hydrate from localStorage on mount
  useEffect(() => {
    setSearchHistory(loadHistory());
  }, []);

  const { data: decksData } = trpc.getDecks.useQuery();
  const addCard = trpc.addCard.useMutation();
  const utils = trpc.useUtils();

  const { data: results, isLoading } = trpc.searchCharacters.useQuery(
    { query, hskLevel: hskFilter },
    { enabled: query.length > 0 }
  );

  const selectedResult = results?.[0];

  const addToHistory = (char: string, pinyin: string, meaning: string) => {
    setSearchHistory(prev => {
      const next = [
        { char, pinyin, meaning, time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) },
        ...prev.filter(h => h.char !== char).slice(0, 9),
      ];
      try { localStorage.setItem(HISTORY_KEY, JSON.stringify(next)); } catch {}
      return next;
    });
  };

  return (
    <div className="flex-1 pt-6 pb-24 md:pb-20 px-4 sm:px-6">
      <div className="max-w-4xl mx-auto">
        {/* Translation Hero Area */}
        <section className="mb-8 sm:mb-12">
          <div className="flex flex-col gap-6">
            {/* Header */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end gap-4">
              <div>
                <span className="text-[0.6875rem] font-bold tracking-[0.2em] text-primary uppercase block mb-1">Translation Studio</span>
                <h2 className="text-2xl sm:text-3xl font-extrabold text-on-background font-[family-name:var(--font-jakarta)] tracking-tight">Refine Your Flow</h2>
              </div>
              <div className="flex gap-2 bg-surface-container-low p-1 rounded-full">
                {[undefined, 1, 2, 3, 4, 5, 6].map(level => (
                  <button key={level ?? 'all'}
                    onClick={() => setHskFilter(level)}
                    className={`px-3 sm:px-4 py-1.5 text-xs font-bold rounded-full transition-colors ${
                      hskFilter === level
                        ? 'bg-surface-container-lowest text-primary shadow-sm'
                        : 'text-on-surface-variant hover:bg-surface-container-high'
                    }`}>
                    {level ? `HSK ${level}` : 'All'}
                  </button>
                ))}
              </div>
            </div>

            {/* Main Translator Card */}
            <div className="bg-surface-container-lowest rounded-2xl sm:rounded-[1.5rem] shadow-[0_32px_64px_-4px_rgba(27,27,35,0.06)] overflow-hidden">
              {/* Language Toggle Bar */}
              <div className="flex items-center justify-center gap-4 sm:gap-8 py-3 sm:py-4 bg-surface-container-low">
                <span className="text-sm font-bold text-on-surface font-[family-name:var(--font-jakarta)]">English</span>
                <div className="w-9 h-9 sm:w-10 sm:h-10 rounded-full bg-primary text-white flex items-center justify-center shadow-lg shadow-primary/20">
                  <span className="material-symbols-outlined text-[20px] sm:text-[24px]">swap_horiz</span>
                </div>
                <span className="text-sm font-bold text-on-surface font-[family-name:var(--font-jakarta)]">Mandarin</span>
              </div>

              {/* Input/Output Grids */}
              <div className="grid grid-cols-1 md:grid-cols-2">
                {/* Input */}
                <div className="p-5 sm:p-8 border-b md:border-b-0 md:border-r border-outline-variant/15">
                  <textarea
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    className="w-full h-36 sm:h-48 bg-transparent border-none focus:ring-0 text-lg sm:text-xl font-medium text-on-background placeholder-outline/50 resize-none outline-none"
                    placeholder="Enter Chinese or English"
                  ></textarea>
                  <div className="flex justify-between items-center mt-3 sm:mt-4">
                    <span className="text-xs text-outline font-medium">{query.length} / 500</span>
                    <button onClick={() => setQuery('')} className="text-outline hover:text-primary transition-colors">
                      <span className="material-symbols-outlined">backspace</span>
                    </button>
                  </div>
                </div>

                {/* Output */}
                <div className="p-5 sm:p-8 bg-surface-bright/30">
                  <div className="h-36 sm:h-48">
                    {isLoading ? (
                      <div className="flex items-center justify-center h-full">
                        <div className="w-8 h-8 border-3 border-primary/30 border-t-primary rounded-full animate-spin"></div>
                      </div>
                    ) : selectedResult ? (
                      <>
                        <p className="text-3xl sm:text-4xl chinese-char text-primary font-bold mb-2 tracking-wide leading-relaxed">{selectedResult.character}</p>
                        <div className="flex items-center gap-2 mb-3 sm:mb-4">
                          <p className="text-base sm:text-lg text-secondary font-medium tracking-widest">{selectedResult.pinyin}</p>
                          <SpeakButton text={selectedResult.character} size="sm" />
                        </div>
                        <p className="text-on-surface-variant leading-relaxed text-sm sm:text-base">{selectedResult.meaning}</p>
                      </>
                    ) : query.length > 0 ? (
                      <p className="text-on-surface-variant text-sm py-4">No results found</p>
                    ) : (
                      <p className="text-outline/50 text-sm py-4">Start typing to search...</p>
                    )}
                  </div>
                  <div className="flex justify-end gap-3 mt-3 sm:mt-4">
                    {selectedResult && (
                      <button onClick={() => addToHistory(selectedResult.character, selectedResult.pinyin, selectedResult.meaning)}
                        className="p-2 text-outline hover:text-primary transition-colors">
                        <span className="material-symbols-outlined text-[20px]">bookmark_add</span>
                      </button>
                    )}
                  </div>
                </div>
              </div>

              {/* Action Bar */}
              {selectedResult && (
                <div className="px-5 sm:px-8 py-4 sm:py-6 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3 bg-surface-container-low/50">
                  <div className="flex gap-2">
                    {selectedResult.hskLevel && (
                      <span className="bg-primary/10 text-primary text-[10px] font-extrabold px-3 py-1 rounded-full uppercase tracking-wider">HSK {selectedResult.hskLevel}</span>
                    )}
                    <span className="bg-secondary/10 text-secondary text-[10px] font-extrabold px-3 py-1 rounded-full uppercase tracking-wider">{selectedResult.deckTitle}</span>
                  </div>
                  <button onClick={async () => {
                    if (!decksData?.length || addingToStudy) return;
                    setAddingToStudy(selectedResult.character);
                    try {
                      await addCard.mutateAsync({
                        deckId: decksData[0].id,
                        character: selectedResult.character,
                        pinyin: selectedResult.pinyin,
                        meaning: selectedResult.meaning,
                        hskLevel: selectedResult.hskLevel ?? undefined,
                      });
                      addToHistory(selectedResult.character, selectedResult.pinyin, selectedResult.meaning);
                      utils.getDecks.invalidate();
                      utils.getDashboardStats.invalidate();
                    } catch {} finally {
                      setAddingToStudy(null);
                    }
                  }}
                    className="flex items-center gap-2 px-5 sm:px-6 py-2.5 sm:py-3 bg-gradient-to-r from-primary to-secondary text-white rounded-full font-bold text-sm shadow-xl shadow-primary/20 transition-transform active:scale-95 w-full sm:w-auto justify-center disabled:opacity-50"
                    disabled={!!addingToStudy || !decksData?.length}>
                    <span className="material-symbols-outlined text-sm">{addingToStudy ? 'hourglass_empty' : 'bookmark_add'}</span>
                    {addingToStudy ? 'Adding...' : `Add to ${decksData?.[0]?.title ?? 'Deck'}`}
                  </button>
                </div>
              )}
            </div>
          </div>
        </section>

        {/* Bottom Sections Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 sm:gap-8">
          {/* Search Results (2/3 width) */}
          <div className="lg:col-span-2 space-y-4 sm:space-y-6">
            <h3 className="text-base sm:text-lg font-bold font-[family-name:var(--font-jakarta)] flex items-center gap-2">
              <span className="w-1.5 h-1.5 bg-primary rounded-full"></span>
              {results && results.length > 0 ? `Results (${results.length})` : 'Search Results'}
            </h3>
            <div className="space-y-3 sm:space-y-4">
              {results && results.length > 0 ? results.slice(0, 10).map((r) => (
                <div key={r.id}
                  onClick={() => { setQuery(r.character); addToHistory(r.character, r.pinyin, r.meaning); }}
                  className="p-4 sm:p-6 bg-surface-container-low rounded-xl sm:rounded-2xl border-l-4 border-primary/20 cursor-pointer hover:bg-surface-container-high transition-colors">
                  <div className="flex items-center gap-4">
                    <span className="text-2xl sm:text-3xl chinese-char text-primary font-bold">{r.character}</span>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm sm:text-base font-medium text-secondary">{r.pinyin}</p>
                      <p className="text-xs sm:text-sm text-on-surface-variant truncate">{r.meaning}</p>
                    </div>
                    {r.hskLevel && (
                      <span className="text-[10px] font-bold text-primary bg-primary/10 px-2 py-1 rounded-full">HSK {r.hskLevel}</span>
                    )}
                  </div>
                </div>
              )) : query.length > 0 && !isLoading ? (
                <div className="p-6 bg-surface-container-low rounded-xl text-center">
                  <p className="text-sm text-on-surface-variant">No matching characters found.</p>
                </div>
              ) : (
                <div className="p-6 bg-surface-container-low rounded-xl text-center">
                  <p className="text-sm text-on-surface-variant">Type a character, pinyin, or English meaning to search.</p>
                </div>
              )}
            </div>
          </div>

          {/* Recent History (1/3 width) */}
          <div className="space-y-4 sm:space-y-6">
            <h3 className="text-base sm:text-lg font-bold font-[family-name:var(--font-jakarta)] flex items-center gap-2">
              <span className="w-1.5 h-1.5 bg-secondary rounded-full"></span>
              Recent History
            </h3>
            <div className="bg-surface-container-lowest rounded-xl sm:rounded-2xl overflow-hidden shadow-sm">
              <div className="divide-y divide-outline-variant/10">
                {searchHistory.length > 0 ? searchHistory.map((item) => (
                  <div key={item.char} onClick={() => setQuery(item.char)}
                    className="p-3 sm:p-4 hover:bg-surface-container-low transition-colors cursor-pointer">
                    <div className="flex justify-between items-start mb-1">
                      <span className="text-sm font-bold font-[family-name:var(--font-jakarta)]">{item.meaning}</span>
                      <span className="text-[10px] text-outline">{item.time}</span>
                    </div>
                    <p className="text-sm sm:text-base chinese-char text-primary">{item.char} ({item.pinyin})</p>
                  </div>
                )) : (
                  <div className="p-4 text-center">
                    <p className="text-xs text-on-surface-variant">No search history yet</p>
                  </div>
                )}
              </div>
