const PAGE_SIZE = 8;

export default function DiscoverPage() {
  usePageTitle('Discover');
  const [hskFilter, setHskFilter] = useState<number | undefined>(undefined);
  const [page, setPage] = useState(0);
  const [savedChars, setSavedChars] = useState<Set<number>>(new Set());

  const { data: stats } = trpc.getDashboardStats.useQuery();
  const { data: decksData } = trpc.getDecks.useQuery();
  const addCard = trpc.addCard.useMutation();
  const utils = trpc.useUtils();
  const { data: results, isLoading } = trpc.searchCharacters.useQuery(
    { query: '%', hskLevel: hskFilter },
    { placeholderData: keepPreviousData }
  );

  const allChars = results ?? [];
  const totalPages = Math.max(1, Math.ceil(allChars.length / PAGE_SIZE));
  const pagedChars = allChars.slice(page * PAGE_SIZE, (page + 1) * PAGE_SIZE);

  return (
    <div className="flex-1 flex flex-col min-w-0">
      <section className="p-4 sm:p-6 lg:p-8 xl:p-12 space-y-8 sm:space-y-12 pb-24 md:pb-8">
        {/* Filters & Categories */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="md:col-span-3 bg-surface-container-low p-4 sm:p-6 rounded-2xl sm:rounded-[1.5rem] flex flex-wrap items-center gap-3 sm:gap-4">
            <span className="text-[10px] font-bold uppercase tracking-[0.15em] text-on-surface-variant w-full md:w-auto mb-1 md:mb-0">HSK Level</span>
            <div className="flex flex-wrap gap-2">
              <button onClick={() => { setHskFilter(undefined); setPage(0); }}
                className={`px-4 sm:px-5 py-1.5 rounded-full text-xs sm:text-sm font-medium transition-colors ${!hskFilter ? 'bg-primary text-white' : 'bg-surface-container-lowest text-on-surface-variant hover:bg-primary-fixed'}`}>
                All
              </button>
              {[1, 2, 3, 4, 5, 6].map((level) => (
                <button key={level} onClick={() => { setHskFilter(level); setPage(0); }}
                  className={`px-4 sm:px-5 py-1.5 rounded-full text-xs sm:text-sm font-medium transition-colors ${hskFilter === level ? 'bg-primary text-white' : 'bg-surface-container-lowest text-on-surface-variant hover:bg-primary-fixed'}`}>
                  HSK {level}
                </button>
              ))}
            </div>
          </div>
          <div className="bg-primary-container text-on-primary-container p-4 sm:p-6 rounded-2xl sm:rounded-[1.5rem] flex items-center justify-between">
            <div>
              <p className="text-[10px] font-bold uppercase tracking-widest opacity-70">Total Found</p>
              <p className="font-bold text-sm sm:text-base">{allChars.length} Characters</p>
            </div>
            <span className="material-symbols-outlined text-2xl sm:text-3xl">filter_list</span>
          </div>
        </div>

        {/* Visual Discovery Grid */}
        {isLoading ? (
          <div className="flex justify-center py-20">
            <div className="w-12 h-12 border-4 border-primary/30 border-t-primary rounded-full animate-spin"></div>
          </div>
        ) : (
          <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-6 lg:gap-8">
            {pagedChars.map((c, i) => (
              <div
                key={c.id}
                className={`group relative bg-surface-container-lowest rounded-2xl sm:rounded-[1.5rem] overflow-hidden transition-all duration-300 hover:translate-y-[-8px] hover:shadow-[0_24px_48px_-12px_rgba(70,72,212,0.12)] ${i === 0 ? "border-2 border-primary/20" : ""}`}
              >
                <div className="aspect-[4/5] p-4 sm:p-6 lg:p-8 flex flex-col items-center justify-center text-center relative z-10">
                  <span className="text-[8px] sm:text-[10px] font-bold uppercase tracking-[0.2em] text-primary mb-2 sm:mb-4">HSK {c.hskLevel ?? '?'}</span>
                  <h2 className="chinese-char text-5xl sm:text-6xl lg:text-7xl font-light mb-2 sm:mb-4 text-on-surface leading-tight tracking-[0.05em]">{c.character}</h2>
                  <p className="text-on-surface-variant font-medium text-sm sm:text-lg italic">{c.pinyin}</p>
                  <p className="text-on-surface text-base sm:text-xl font-bold mt-1 sm:mt-2">{c.meaning}</p>
                  <div className="mt-4 sm:mt-8 flex gap-3 sm:gap-4 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                    <SpeakButton text={c.character} size="md" />
                    <button
                      onClick={async (e) => {
                        e.stopPropagation();
                        if (!decksData?.length || savedChars.has(c.id)) return;
                        try {
                          await addCard.mutateAsync({
                            deckId: decksData[0].id,
                            character: c.character,
                            pinyin: c.pinyin,
                            meaning: c.meaning,
                            hskLevel: c.hskLevel ?? undefined,
                          });
                          setSavedChars(prev => new Set(prev).add(c.id));
                          utils.getDecks.invalidate();
                          utils.getDashboardStats.invalidate();
                        } catch {}
                      }}
                      className={`p-1.5 rounded-full transition-colors ${
                        savedChars.has(c.id)
                          ? 'text-secondary'
                          : 'text-primary hover:bg-primary-fixed'
                      }`}
                      aria-label={savedChars.has(c.id) ? 'Saved to deck' : 'Save to deck'}
                    >
                      <span className="material-symbols-outlined text-[20px] sm:text-[24px]" style={savedChars.has(c.id) ? { fontVariationSettings: "'FILL' 1" } : {}}>
                        {savedChars.has(c.id) ? 'bookmark_added' : 'bookmark'}
                      </span>
                    </button>
                  </div>
                </div>
                {/* Background Image Layer */}
                <div className="absolute inset-0 z-0 opacity-10 grayscale group-hover:grayscale-0 group-hover:opacity-30 transition-all duration-500 scale-110 group-hover:scale-100">
                  <img className="w-full h-full object-cover" src={discoverImages[i % discoverImages.length]} alt={c.meaning} />
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Footer Stats */}
        <div className="flex flex-col sm:flex-row justify-between items-center py-8 sm:py-12 border-t border-outline-variant/15 text-on-surface-variant gap-4">
          <div className="flex gap-6 sm:gap-8">
            <div>
              <span className="block text-[10px] font-bold uppercase tracking-widest opacity-60">Total Characters</span>
              <span className="text-lg sm:text-xl font-bold text-on-surface">{stats?.totalCards ?? 0}</span>
            </div>
            <div>
              <span className="block text-[10px] font-bold uppercase tracking-widest opacity-60">Showing</span>
              <span className="text-lg sm:text-xl font-bold text-on-surface">{allChars.length}</span>
            </div>
          </div>
          <div className="flex gap-3 sm:gap-4">
            <button onClick={() => setPage(p => Math.max(0, p - 1))} disabled={page === 0}
              className="p-3 sm:p-4 rounded-xl bg-surface-container-low hover:bg-surface-container-high transition-colors disabled:opacity-30">
              <span className="material-symbols-outlined text-[20px] sm:text-[24px]">chevron_left</span>
            </button>
            <div className="flex items-center px-4 sm:px-6 font-bold text-sm sm:text-base">{page + 1} / {totalPages}</div>
            <button onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))} disabled={page >= totalPages - 1}
              className="p-3 sm:p-4 rounded-xl bg-surface-container-low hover:bg-surface-container-high transition-colors disabled:opacity-30">
              <span className="material-symbols-outlined text-[20px] sm:text-[24px]">chevron_right</span>
            </button>
          </div>
        </div>
      </section>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { trpc } from '@/trpc/client';
import { Flashcard } from '@/components/Flashcard';
import { SpeakButton } from '@/components/SpeakButton';
import Link from 'next/link';
import { usePageTitle } from '@/hooks/usePageTitle';

export default function FlashcardsPage() {
  usePageTitle('Flashcards');
  const { data: decksData } = trpc.getDecks.useQuery();
  const [selectedDeckId, setSelectedDeckId] = useState<number | null>(null);
  const { data: cards } = trpc.getCardsForDeck.useQuery(
    { deckId: selectedDeckId! },
    { enabled: !!selectedDeckId }
  );

  const [currentIndex, setCurrentIndex] = useState(0);
  const [mastered, setMastered] = useState(0);
  const [again, setAgain] = useState(0);

  const decks = decksData ?? [];
  const cardList = cards ?? [];
  const card = cardList[currentIndex];
  const total = cardList.length;

  const handleResult = (correct: boolean) => {
    if (correct) {
      setMastered(m => m + 1);
    } else {
      setAgain(a => a + 1);
    }
    // Small delay for animation before advancing
    setTimeout(() => {
      setCurrentIndex(i => Math.min(total - 1, i + 1));
    }, 200);
  };

  const handleNext = () => {
    setCurrentIndex(i => Math.min(total - 1, i + 1));
  };

  const handlePrev = () => {
    setCurrentIndex(i => Math.max(0, i - 1));
  };

  // Keyboard navigation: arrow keys for prev/next
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (e.key === 'ArrowRight') handleNext();
      if (e.key === 'ArrowLeft') handlePrev();
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, []);

  // Deck selector
  if (!selectedDeckId) {
    return (
      <div className="max-w-6xl mx-auto px-4 sm:px-6 py-6 sm:py-12 pb-24 md:pb-8">
        <div className="space-y-2 mb-8">
          <span className="text-[0.625rem] sm:text-[0.6875rem] font-bold tracking-[0.1em] text-primary uppercase">Flashcards</span>
          <h1 className="text-xl sm:text-2xl font-[family-name:var(--font-jakarta)] font-extrabold text-on-surface">Choose a Deck</h1>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6" role="list" aria-label="Available decks">
          {decks.map(d => (
            <button key={d.id} onClick={() => { setSelectedDeckId(d.id); setCurrentIndex(0); setMastered(0); setAgain(0); }}
              className="bg-surface-container-lowest rounded-xl p-6 sm:p-8 text-left hover:bg-primary-fixed transition-colors group" role="listitem" aria-label={`${d.title}, ${d.cardCount} cards`}>
              <h3 className="text-lg sm:text-xl font-[family-name:var(--font-jakarta)] font-bold text-on-surface group-hover:text-primary mb-2">{d.title}</h3>
              <p className="text-sm text-on-surface-variant">{d.description}</p>
              <div className="mt-4 flex items-center gap-2">
                <span className="text-xs font-bold text-primary bg-primary/10 px-3 py-1 rounded-full">{d.cardCount} cards</span>
              </div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  // Session complete — all cards reviewed
  if (currentIndex >= total && total > 0) {
    return (
      <div className="max-w-6xl mx-auto px-4 sm:px-6 py-6 sm:py-12 flex flex-col items-center justify-center pb-24 md:pb-8 text-center space-y-6">
        <span className="material-symbols-outlined text-6xl text-primary" style={{ fontVariationSettings: "'FILL' 1" }}>celebration</span>
        <h1 className="text-2xl sm:text-3xl font-[family-name:var(--font-jakarta)] font-bold text-on-surface">Deck Complete!</h1>
        <div className="flex gap-6 text-sm">
          <div className="text-center">
            <span className="text-2xl font-bold text-primary block">{mastered}</span>
            <span className="text-on-surface-variant">Got It</span>
          </div>
          <div className="text-center">
            <span className="text-2xl font-bold text-error block">{again}</span>
            <span className="text-on-surface-variant">Again</span>
          </div>
        </div>
        <div className="flex gap-3">
          <button onClick={() => { setCurrentIndex(0); setMastered(0); setAgain(0); }} className="px-6 py-3 bg-gradient-to-r from-primary to-secondary text-white rounded-full font-bold shadow-xl shadow-primary/20 hover:opacity-90 transition-all">
            Restart Deck
          </button>
          <button onClick={() => setSelectedDeckId(null)} className="px-6 py-3 bg-surface-container-high text-on-surface rounded-full font-bold hover:bg-surface-container-highest transition-colors">
            Choose Another
          </button>
        </div>
      </div>
    );
  }

  if (!card) {
    return (
      <div className="max-w-6xl mx-auto px-4 sm:px-6 py-6 sm:py-12 flex flex-col items-center justify-center pb-24 md:pb-8">
        <p className="text-on-surface-variant text-sm mb-4">No cards in this deck.</p>
        <button onClick={() => setSelectedDeckId(null)} className="text-primary font-bold text-sm hover:underline">← Back to decks</button>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto px-4 sm:px-6 py-6 sm:py-12 flex flex-col items-center pb-24 md:pb-8">
      {/* Progress Header */}
      <div className="w-full max-w-2xl mb-8 sm:mb-12 flex flex-col gap-3 sm:gap-4">
        <div className="flex justify-between items-end">
          <div>
            <button onClick={() => setSelectedDeckId(null)} className="text-[0.625rem] sm:text-[0.6875rem] font-bold tracking-[0.1em] text-primary uppercase hover:underline" aria-label="Go back to deck selection">
              ← {decks.find(d => d.id === selectedDeckId)?.title ?? 'Deck'}
            </button>
            <h1 className="text-xl sm:text-2xl font-[family-name:var(--font-jakarta)] font-extrabold text-on-surface">Flashcard Review</h1>
          </div>
          <div className="text-right">
            <span className="text-xs sm:text-sm font-medium text-on-surface-variant">Card {currentIndex + 1} of {total}</span>
          </div>
        </div>
        <div className="w-full h-1.5 bg-surface-container-high rounded-full overflow-hidden" role="progressbar" aria-valuenow={Math.round(((currentIndex + 1) / total) * 100)} aria-valuemax={100}>
          <div className="h-full bg-gradient-to-r from-primary to-secondary rounded-full transition-all duration-300" style={{ width: `${((currentIndex + 1) / total) * 100}%` }}></div>
        </div>
      </div>

      {/* Framer Motion Flashcard Component */}
      <Flashcard
        key={card.id}
        character={card.character}
        pinyin={card.pinyin}
        meaning={card.meaning}
        onResult={handleResult}
      />

      {/* Navigation Controls */}
      <div className="w-full max-w-sm mt-8 sm:mt-12 flex gap-3 sm:gap-4">
        <button onClick={handlePrev} disabled={currentIndex === 0}
          className="flex-1 flex items-center justify-center gap-2 sm:gap-3 p-4 sm:p-6 bg-surface-container-low text-on-surface-variant rounded-xl hover:bg-surface-container-high transition-all active:scale-95 text-sm sm:text-base disabled:opacity-30"
          aria-label="Previous card (Left Arrow)">
          <span className="material-symbols-outlined text-[20px] sm:text-[24px]">chevron_left</span>
          <span className="font-bold">Prev</span>
        </button>
        <button onClick={handleNext} disabled={currentIndex >= total - 1}
          className="flex-[1.5] flex items-center justify-center gap-2 sm:gap-3 p-4 sm:p-6 bg-gradient-to-r from-primary to-secondary text-on-primary rounded-full shadow-lg shadow-primary/20 hover:opacity-90 transition-all active:scale-95 text-sm sm:text-base disabled:opacity-50"
          aria-label="Next card (Right Arrow)">
          <span className="font-bold">Next</span>
          <span className="material-symbols-outlined text-[20px] sm:text-[24px]">arrow_forward</span>
        </button>
      </div>

      {/* Session Stats Bar */}
      <div className="flex gap-8 mt-8 sm:mt-12 text-center">
        <div>
          <span className="text-lg font-bold text-primary">{mastered}</span>
          <span className="text-[10px] text-on-surface-variant block uppercase tracking-wider font-bold">Got It</span>
        </div>
        <div>
          <span className="text-lg font-bold text-error">{again}</span>
          <span className="text-[10px] text-on-surface-variant block uppercase tracking-wider font-bold">Again</span>
        </div>
        <div>
          <span className="text-lg font-bold text-on-surface">{total - currentIndex - 1}</span>
          <span className="text-[10px] text-on-surface-variant block uppercase tracking-wider font-bold">Remaining</span>
        </div>
      </div>

      {/* Keyboard Hint + TTS */}
      <div className="mt-6 flex items-center justify-center gap-4">
        <SpeakButton text={card.character} size="md" />
        <p className="text-[10px] text-on-surface-variant/60">
          <kbd className="px-1.5 py-0.5 bg-surface-container-high rounded font-mono text-[9px]">←</kbd> Previous ·
          <kbd className="px-1.5 py-0.5 bg-surface-container-high rounded font-mono text-[9px] ml-1">→</kbd> Next ·
          Click card to flip · Swipe to rate
        </p>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { 
  createColumnHelper, 
  flexRender, 
  getCoreRowModel, 
  useReactTable 
} from '@tanstack/react-table';
import { ChevronRight, Save, Upload } from 'lucide-react';
import Link from 'next/link';

const CardSchema = z.object({
  character: z.string().min(1, "Character needed"),
  pinyin: z.string().min(1, "Pinyin needed"),
  meaning: z.string().min(1, "Meaning needed"),
});

const DeckSchema = z.object({
  title: z.string().min(2, "Title must be at least 2 characters"),
  description: z.string().optional(),
});

type CardData = z.infer<typeof CardSchema>;
type DeckDetails = z.infer<typeof DeckSchema>;

export default function NewDeckPage() {
  const [cards, setCards] = useState<CardData[]>([]);
  const [pasteData, setPasteData] = useState("");

  const { register, handleSubmit, formState: { errors } } = useForm<DeckDetails>({
    resolver: zodResolver(DeckSchema),
  });

  const handleParse = () => {
    // Basic CSV/TSV parser: "好 hǎo good" or "好,hǎo,good"
    const lines = pasteData.split('\n');
    const parsed: CardData[] = [];
    lines.forEach(line => {
      if (!line.trim()) return;
      const parts = line.split(/[\t,]/).map(s => s.trim());
      if (parts.length >= 3) {
        parsed.push({
          character: parts[0],
          pinyin: parts[1],
          meaning: parts.slice(2).join(' '), // In case meaning had commas
        });
      }
    });
    setCards(parsed);
  };

  const onSubmit = (data: DeckDetails) => {
    console.log("Saving deck:", data, "with cards:", cards);
    // Ideally mutation.mutate({ ...data, cards })
    alert("Deck Saved successfully! Redirecting...");
  };

  const columnHelper = createColumnHelper<CardData>();
  const columns = [
    columnHelper.accessor('character', { header: 'Character', cell: info => info.getValue() }),
    columnHelper.accessor('pinyin', { header: 'Pinyin', cell: info => info.getValue() }),
    columnHelper.accessor('meaning', { header: 'Meaning', cell: info => info.getValue() }),
  ];

  const table = useReactTable({
    data: cards,
    columns,
    getCoreRowModel: getCoreRowModel(),
  });

  return (
    <div className="max-w-5xl mx-auto py-6">
       <div className="flex items-center gap-2 text-sm text-slate-500 mb-6">
          <Link href="/decks" className="hover:text-slate-800">Decks</Link>
          <ChevronRight size={14} />
          <span className="text-slate-800 font-medium">Import new deck</span>
       </div>

       <div className="flex justify-between items-end mb-8">
          <div>
             <h1 className="text-3xl font-bold text-slate-800">Import Flashcards</h1>
             <p className="text-slate-500 mt-2">Paste your words list from Excel, Pleco, or Quizlet.</p>
          </div>
       </div>

       <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1 space-y-6">
            <form id="deckForm" onSubmit={handleSubmit(onSubmit)} className="space-y-4 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Deck Title</label>
                  <input {...register('title')} className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="e.g. HSK 1 Vocabulary" />
                  {errors.title && <p className="text-red-500 text-sm mt-1">{errors.title.message}</p>}
               </div>
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Description (Optional)</label>
                  <textarea {...register('description')} className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="Describe the focus of this deck..." rows={3} />
               </div>
            </form>

             <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
               <h3 className="font-medium text-slate-800 mb-4 flex items-center gap-2">
                 <Upload size={18} className="text-blue-600" /> Bulk Import
               </h3>
               <p className="text-xs text-slate-500 mb-3">Paste exactly 3 columns: Character, Pinyin, Meaning separated by Tab or Comma.</p>
               <textarea 
                  value={pasteData}
                  onChange={(e) => setPasteData(e.target.value)}
                  className="w-full border border-slate-300 rounded-lg p-2.5 mb-3 focus:ring-2 focus:ring-blue-500 outline-none text-sm font-mono" 
                  rows={6} 
                  placeholder="好   hǎo   good&#10;人   rén   person"
               />
               <button type="button" onClick={handleParse} className="w-full py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition text-sm font-medium">
                 Parse Cards
               </button>
             </div>
          </div>

          <div className="lg:col-span-2">
             <div className="bg-white border text-sm border-slate-200 rounded-2xl shadow-sm overflow-hidden flex flex-col h-full min-h-[500px]">
                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
                   <h3 className="font-semibold text-slate-800">Preview ({cards.length} cards)</h3>
                   <button 
                      form="deckForm"
                      type="submit"
                      disabled={cards.length === 0} 
                      className="px-4 py-2 bg-blue-600 disabled:opacity-50 text-white rounded-lg shadow-sm font-medium hover:bg-blue-700 transition flex items-center gap-2 text-sm"
                   >
                     <Save size={16} /> Save Deck
                   </button>
                </div>
                
                {cards.length === 0 ? (
                  <div className="flex-1 flex items-center justify-center text-slate-400 p-8 text-center flex-col gap-4">
                     <p>Paste data and click "Parse Cards" to preview your import.</p>
                  </div>
                ) : (
                  <div className="overflow-x-auto">
                     <table className="w-full text-left border-collapse">
                        <thead>
                           {table.getHeaderGroups().map(headerGroup => (
                              <tr key={headerGroup.id} className="border-b border-slate-200">
                                 {headerGroup.headers.map(header => (
                                    <th key={header.id} className="p-4 font-semibold text-slate-600 bg-slate-50">
                                       {flexRender(header.column.columnDef.header, header.getContext())}
                                    </th>
                                 ))}
                              </tr>
                           ))}
                        </thead>
                        <tbody>
                           {table.getRowModel().rows.map(row => (
                              <tr key={row.id} className="border-b border-slate-100 hover:bg-slate-50/50">
                                 {row.getVisibleCells().map(cell => (
                                    <td key={cell.id} className="p-4 text-slate-700">
                                       {flexRender(cell.column.columnDef.cell, cell.getContext())}
                                    </td>
                                 ))}
                              </tr>
                           ))}
                        </tbody>
                     </table>
                  </div>
                )}
             </div>
          </div>
       </div>
    </div>
  );
}

