            <Link href="/practice" className="text-primary text-xs font-bold hover:underline" aria-label="View all cards due for review">View All</Link>
          </div>
          <div className="space-y-4 sm:space-y-6">
            {cardsLoading ? (
              Array.from({ length: 3 }).map((_, i) => (
