                  <div className="w-12 h-12 sm:w-16 sm:h-16 bg-surface-container-high rounded-xl flex-shrink-0" />
                  <div className="flex-1 space-y-2">
                    <div className="h-4 w-20 bg-surface-container-high rounded" />
