'use client';

import { useState, useEffect, useCallback } from 'react';
import React from 'react';
import { trpc } from '@/trpc/client';
import { SpeakButton } from '@/components/SpeakButton';
import { usePageTitle } from '@/hooks/usePageTitle';
import Link from 'next/link';

/**
 * Reverse Practice: Show English meaning → user selects the correct Chinese character.
 * Tests productive recall (harder than recognition).
 */
export default function ReversePracticePage() {
  usePageTitle('Reverse Practice');
  const { data: dueCards, isLoading, refetch } = trpc.getDueCards.useQuery({ limit: 20 });
  const submitReview = trpc.submitReview.useMutation({ onSuccess: () => refetch() });
  const recordActivity = trpc.recordStudyActivity.useMutation();
  const awardXP = trpc.awardXP.useMutation();
  const updateChallenge = trpc.updateChallengeProgress.useMutation();

  const [currentIndex, setCurrentIndex] = useState(0);
  const [options, setOptions] = useState<string[]>([]);
  const [selected, setSelected] = useState<string | null>(null);
  const [answered, setAnswered] = useState(false);
  const [score, setScore] = useState(0);
  const [streak, setStreak] = useState(0);
  const [startTime, setStartTime] = useState(() => Date.now());

  const cards = React.useMemo(() => dueCards ?? [], [dueCards]);
  const total = cards.length;
  const card = cards[currentIndex];

  // Generate options whenever card changes
  useEffect(() => {
    if (!card || cards.length < 2) return;

    const correctChar = card.character;
    const distractors = cards
      .filter(c => c.character !== correctChar)
      .sort(() => Math.random() - 0.5)
      .slice(0, 3)
      .map(c => c.character);

    const opts = [...distractors, correctChar].sort(() => Math.random() - 0.5);
    setOptions(opts);
    setStartTime(Date.now());
  }, [card, cards]);

  const handleSelect = useCallback((char: string) => {
    if (answered || !card) return;
    setSelected(char);
    setAnswered(true);

    const isCorrect = char === card.character;
    const responseTimeMs = Date.now() - startTime;
    const quality = isCorrect ? (responseTimeMs < 3000 ? 5 : responseTimeMs < 6000 ? 4 : 3) : 1;

    submitReview.mutate({ progressId: card.progressId, quality, responseTimeMs });
    recordActivity.mutate({ cardsReviewed: 1, cardsCorrect: isCorrect ? 1 : 0 });

    if (isCorrect) {
      setScore(s => s + 1);
      setStreak(s => s + 1);
      const xp = quality >= 5 ? 18 : quality >= 4 ? 14 : 10; // Bonus for reverse mode
      awardXP.mutate({ xpAmount: xp, source: 'review' });
      updateChallenge.mutate({ challengeType: 'review_count', increment: 1 });
      if (quality >= 5) updateChallenge.mutate({ challengeType: 'perfect_recall', increment: 1 });
    } else {
      setStreak(0);
    }
  }, [answered, card, startTime, submitReview, recordActivity, awardXP, updateChallenge]);

  const handleNext = useCallback(() => {
    setSelected(null);
    setAnswered(false);
    setCurrentIndex(i => i + 1);
  }, []);

  // Keyboard shortcuts
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement) return;
      if (!answered && options.length > 0) {
        const idx = ['1', '2', '3', '4'].indexOf(e.key);
        if (idx >= 0 && idx < options.length) {
          e.preventDefault();
          handleSelect(options[idx]);
        }
      }
      if (answered && (e.key === 'Enter' || e.key === ' ')) {
        e.preventDefault();
        handleNext();
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [answered, options, handleSelect, handleNext]);

  // Session complete
  if (!isLoading && (total === 0 || currentIndex >= total)) {
    return (
      <div className="flex-1 flex items-center justify-center px-4 pb-24 md:pb-8">
        <div className="text-center space-y-6 max-w-sm">
          <span className="material-symbols-outlined text-6xl text-primary" style={{ fontVariationSettings: "'FILL' 1" }}>celebration</span>
          <h1 className="text-2xl sm:text-3xl font-[family-name:var(--font-jakarta)] font-bold text-on-surface">
            {total === 0 ? 'No Cards Due!' : 'Session Complete!'}
          </h1>
          {total > 0 && (
            <div className="flex justify-center gap-6 bg-surface-container-low p-4 rounded-xl">
              <div className="text-center">
                <span className="text-2xl font-bold text-primary block">{score}</span>
                <span className="text-on-surface-variant text-xs">Correct</span>
              </div>
              <div className="text-center">
                <span className="text-2xl font-bold text-on-surface block">{total}</span>
                <span className="text-on-surface-variant text-xs">Total</span>
              </div>
              <div className="text-center">
                <span className="text-2xl font-bold text-secondary block">{total > 0 ? Math.round((score / total) * 100) : 0}%</span>
                <span className="text-on-surface-variant text-xs">Accuracy</span>
              </div>
            </div>
          )}
          <div className="flex gap-3">
            <Link href="/practice" className="flex-1 px-6 py-3 bg-surface-container-high text-on-surface rounded-full font-bold text-sm text-center hover:bg-surface-container-highest transition-colors">
              Standard Mode
            </Link>
            <button
              onClick={() => { setCurrentIndex(0); setScore(0); setStreak(0); refetch(); }}
              className="flex-1 px-6 py-3 bg-gradient-to-r from-primary to-secondary text-white rounded-full font-bold text-sm shadow-xl shadow-primary/20 hover:opacity-90 transition-all"
            >
              Try Again
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (isLoading || !card) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-primary/30 border-t-primary rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="flex-1 flex flex-col px-4 sm:px-6 py-6 sm:py-8 max-w-4xl mx-auto w-full pb-24 md:pb-8">
      {/* Header */}
      <div className="flex justify-between items-center mb-8">
        <div>
          <span className="text-[0.625rem] font-bold uppercase tracking-[0.15em] text-secondary">Reverse Mode</span>
          <h1 className="text-xl sm:text-2xl font-[family-name:var(--font-jakarta)] font-bold text-on-surface">Meaning → Character</h1>
        </div>
        <div className="flex items-center gap-4 text-sm">
          {streak > 0 && <span className="font-bold text-secondary">{streak}🔥</span>}
          <span className="font-medium text-on-surface-variant">{currentIndex + 1} / {total}</span>
        </div>
      </div>

      {/* Progress */}
      <div className="h-2 w-full bg-surface-container-high rounded-full overflow-hidden mb-10">
        <div className="h-full bg-gradient-to-r from-secondary to-primary rounded-full transition-all duration-500" style={{ width: `${((currentIndex) / total) * 100}%` }} />
      </div>

      {/* The Prompt: Show meaning + pinyin */}
      <div className="bg-surface-container-lowest rounded-2xl sm:rounded-[2.5rem] p-8 sm:p-12 text-center shadow-[0_32px_64px_-4px_rgba(27,27,35,0.06)] mb-8 relative overflow-hidden">
        <div className="absolute top-4 right-5 bg-surface-container-low px-3 py-1 rounded-full">
          <span className="text-[0.5rem] font-bold text-secondary uppercase tracking-widest">Find the Character</span>
        </div>
        <p className="text-2xl sm:text-4xl font-[family-name:var(--font-jakarta)] font-black text-on-surface mt-6 mb-3">
          {card.meaning}
        </p>
        <p className="text-lg text-primary font-medium">{card.pinyin}</p>
        <SpeakButton text={card.character} size="lg" className="mt-3" />
      </div>

      {/* Options grid */}
      <div className="grid grid-cols-2 gap-3 sm:gap-4">
        {options.map((opt, i) => {
          const isSelected = selected === opt;
          const isCorrect = opt === card.character;
          const showCorrect = answered && isCorrect;
          const showWrong = answered && isSelected && !isCorrect;

          return (
            <button
              key={`${opt}-${i}`}
              onClick={() => handleSelect(opt)}
              disabled={answered}
              className={`p-6 sm:p-8 rounded-2xl transition-all text-center ${
                showCorrect
                  ? 'bg-primary-fixed border-2 border-primary ring-2 ring-primary/20'
                  : showWrong
                    ? 'bg-error-container border-2 border-error ring-2 ring-error/20'
                    : 'bg-surface-container-lowest border-2 border-transparent hover:border-primary/20 hover:bg-surface-container-low'
              }`}
            >
              <span className="chinese-char text-4xl sm:text-5xl font-bold text-on-surface block mb-2">
                {opt}
              </span>
              <kbd className="text-[10px] text-outline font-mono">{i + 1}</kbd>
            </button>
          );
        })}
      </div>

      {/* Next button */}
      {answered && (
        <button
          onClick={handleNext}
          className="mt-6 w-full py-4 bg-gradient-to-r from-primary to-secondary text-white rounded-full font-bold shadow-xl shadow-primary/20 hover:opacity-90 transition-all flex items-center justify-center gap-2"
        >
          Next <span className="material-symbols-outlined text-[20px]">arrow_forward</span>
        </button>
      )}

      {/* Keyboard shortcuts */}
      <div className="hidden lg:flex fixed bottom-4 left-1/2 -translate-x-1/2 bg-surface-container-low/90 backdrop-blur-md rounded-full px-6 py-2 shadow-lg items-center gap-4 text-[10px] text-on-surface-variant font-medium z-20 border border-outline-variant/20">
        <span><kbd className="px-1.5 py-0.5 bg-surface-container-high rounded font-mono text-[9px]">1-4</kbd> Select</span>
        <span className="text-outline">·</span>
        <span><kbd className="px-1.5 py-0.5 bg-surface-container-high rounded font-mono text-[9px]">Enter</kbd> Next</span>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import { trpc } from '@/trpc/client';
import { SpeakButton } from '@/components/SpeakButton';
import { usePageTitle } from '@/hooks/usePageTitle';
import type HanziWriterType from 'hanzi-writer';

type StrokeMode = 'animate' | 'quiz';

const PRESET_CHARS = [
  { char: '永', name: 'Yǒng', meaning: 'Eternity' },
  { char: '人', name: 'Rén', meaning: 'Person' },
  { char: '大', name: 'Dà', meaning: 'Big' },
  { char: '中', name: 'Zhōng', meaning: 'Middle' },
  { char: '学', name: 'Xué', meaning: 'Study' },
  { char: '书', name: 'Shū', meaning: 'Book' },
  { char: '龙', name: 'Lóng', meaning: 'Dragon' },
  { char: '爱', name: 'Ài', meaning: 'Love' },
];

export default function StrokesPage() {
  usePageTitle('Strokes');
  const writerRef = useRef<HanziWriterType | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [selectedChar, setSelectedChar] = useState('永');
  const [mode, setMode] = useState<StrokeMode>('animate');
  const [quizResult, setQuizResult] = useState<{ correct: number; total: number } | null>(null);
  const [customChar, setCustomChar] = useState('');
  const [writerReady, setWriterReady] = useState(false);

  const { data: decksData } = trpc.getDecks.useQuery();
  const { data: cards } = trpc.getCardsForDeck.useQuery(
    { deckId: decksData?.[0]?.id ?? 0 },
    { enabled: !!decksData?.[0]?.id }
  );

  // Build a merged character list: presets + user's cards
  const userChars = (cards ?? []).slice(0, 12).map(c => ({
    char: c.character,
    name: c.pinyin,
    meaning: c.meaning,
  }));

  const allChars = [
    ...PRESET_CHARS,
    ...userChars.filter(uc => !PRESET_CHARS.some(p => p.char === uc.char)),
  ];

  const currentInfo = allChars.find(c => c.char === selectedChar) ?? {
    char: selectedChar,
    name: '',
    meaning: '',
  };

  const initWriter = useCallback(async (char: string, writerMode: StrokeMode) => {
    // Clean up previous writer
    if (writerRef.current) {
      writerRef.current.hideCharacter();
      writerRef.current = null;
    }
    if (containerRef.current) {
      containerRef.current.innerHTML = '';
    }

    if (!containerRef.current) return;

    const size = Math.min(containerRef.current.clientWidth, containerRef.current.clientHeight, 400);

    try {
      // Dynamic import — keeps HanziWriter out of the initial bundle
      const { default: HanziWriter } = await import('hanzi-writer');
      const writer = HanziWriter.create(containerRef.current!, char, {
        width: size,
        height: size,
        padding: 20,
        showOutline: true,
        showCharacter: writerMode === 'animate',
        strokeAnimationSpeed: 1,
        delayBetweenStrokes: 300,
        strokeColor: '#4648d4',
        outlineColor: '#e4e1ed',
        drawingColor: '#8127cf',
        highlightColor: '#c0c1ff',
        radicalColor: '#4b41e1',
        drawingWidth: 6,
        showHintAfterMisses: 2,
      });

      writerRef.current = writer;
      setWriterReady(true);

      if (writerMode === 'animate') {
        writer.animateCharacter();
      } else {
        setQuizResult(null);
        let correct = 0;
        const total = 0;

        let strokeCount = 0;

        writer.quiz({
          onMistake: () => {},
          onCorrectStroke: (strokeData) => {
            correct = strokeData.strokeNum + 1;
            strokeCount = strokeData.strokeNum + 1;
          },
          onComplete: (summary) => {
            const totalStrokes = strokeCount || correct;
            setQuizResult({
              correct: Math.max(0, totalStrokes - summary.totalMistakes),
              total: totalStrokes,
            });
            // Auto-advance to next character after 2s
            setTimeout(() => {
              const currentIdx = allChars.findIndex(c => c.char === char);
              if (currentIdx >= 0 && currentIdx < allChars.length - 1) {
                setSelectedChar(allChars[currentIdx + 1].char);
              }
            }, 2000);
          },
        });
      }
    } catch {
      // Character not in HanziWriter database
      if (containerRef.current) {
        containerRef.current.innerHTML = `<div class="flex flex-col items-center justify-center h-full text-on-surface-variant">
          <span class="material-symbols-outlined text-5xl text-outline mb-4">error_outline</span>
          <p class="text-sm font-medium">Character "${char}" not available for stroke practice</p>
        </div>`;
      }
    }
  }, []);

  useEffect(() => {
    initWriter(selectedChar, mode);
    return () => {
      if (writerRef.current) {
        writerRef.current.hideCharacter();
        writerRef.current = null;
      }
    };
  }, [selectedChar, mode, initWriter]);

  const handleAnimate = () => {
    if (mode === 'animate' && writerRef.current) {
      writerRef.current.animateCharacter();
    } else {
      setMode('animate');
    }
  };

  const handleQuiz = () => {
    setMode('quiz');
  };

  const handleCustomChar = () => {
    if (customChar.trim()) {
      setSelectedChar(customChar.trim()[0]); // Take first character
      setCustomChar('');
    }
  };

  return (
    <div className="flex-1 p-4 sm:p-6 md:p-8 max-w-6xl mx-auto w-full pb-24 md:pb-8">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 sm:gap-6 lg:gap-8 items-start">
        {/* Character Info & Controls */}
        <div className="lg:col-span-4 space-y-4 sm:space-y-6 order-2 lg:order-1">
          <div className="bg-surface-container-low rounded-xl p-5 sm:p-8">
            <div className="mb-4 sm:mb-6">
              <span className="text-[10px] font-bold tracking-[0.2em] text-primary uppercase">Current Character</span>
              <div className="flex items-center gap-3 mt-2">
                <h3 className="text-3xl sm:text-4xl font-black">{selectedChar} ({currentInfo.name})</h3>
                <SpeakButton text={selectedChar} size="md" />
              </div>
              <p className="text-on-surface-variant mt-2 text-xs sm:text-sm leading-relaxed">
                {currentInfo.meaning || 'Practice writing this character stroke by stroke.'}
              </p>
            </div>

            {/* Mode Toggle */}
            <div className="flex gap-2 mb-4">
              <button
                onClick={handleAnimate}
                className={`flex-1 py-2.5 rounded-xl font-bold text-sm transition-colors flex items-center justify-center gap-2 ${
                  mode === 'animate'
                    ? 'bg-primary text-on-primary'
                    : 'bg-surface-container-high text-on-surface hover:bg-surface-container-highest'
                }`}
              >
                <span className="material-symbols-outlined text-[18px]">play_arrow</span>
                Animate
              </button>
              <button
                onClick={handleQuiz}
                className={`flex-1 py-2.5 rounded-xl font-bold text-sm transition-colors flex items-center justify-center gap-2 ${
                  mode === 'quiz'
                    ? 'bg-secondary text-on-secondary'
                    : 'bg-surface-container-high text-on-surface hover:bg-surface-container-highest'
                }`}
              >
                <span className="material-symbols-outlined text-[18px]">edit_note</span>
                Practice
              </button>
            </div>

            {/* Quiz Result */}
            {quizResult && (
              <div className={`p-4 rounded-xl text-sm font-medium flex items-center gap-2 mb-4 ${
                quizResult.correct === quizResult.total
                  ? 'bg-primary-fixed text-primary'
                  : 'bg-secondary-fixed text-secondary'
              }`}>
                <span className="material-symbols-outlined" style={{ fontVariationSettings: "'FILL' 1" }}>
                  {quizResult.correct === quizResult.total ? 'check_circle' : 'info'}
                </span>
                {quizResult.correct === quizResult.total
                  ? 'Perfect! All strokes correct!'
                  : `${quizResult.correct}/${quizResult.total} strokes correct. Try again!`}
              </div>
            )}

            {/* Custom character input */}
            <div className="flex gap-2">
              <input
                value={customChar}
                onChange={(e) => setCustomChar(e.target.value)}
                placeholder="Enter any character..."
                className="flex-1 px-4 py-2.5 bg-surface-container-lowest rounded-xl text-sm outline-none focus:ring-2 focus:ring-primary/20 chinese-char"
                maxLength={4}
                onKeyDown={(e) => e.key === 'Enter' && handleCustomChar()}
              />
              <button
                onClick={handleCustomChar}
                disabled={!customChar.trim()}
                className="px-4 py-2.5 bg-primary text-on-primary rounded-xl font-bold text-sm disabled:opacity-50 transition-opacity"
              >
                Go
              </button>
            </div>
          </div>

          {/* Character Palette from user's cards */}
          <div className="bg-surface-container-low rounded-xl p-5 sm:p-8">
            <h4 className="text-[10px] sm:text-xs font-bold uppercase tracking-wider text-outline mb-3 sm:mb-4">Quick Select</h4>
            <div className="grid grid-cols-4 gap-2">
              {allChars.slice(0, 16).map((c) => (
                <button
                  key={c.char}
                  onClick={() => setSelectedChar(c.char)}
                  className={`p-3 rounded-xl flex flex-col items-center justify-center transition-all ${
                    selectedChar === c.char
                      ? 'bg-primary text-on-primary'
                      : 'bg-surface-container-lowest text-on-surface hover:bg-primary-fixed hover:text-primary'
                  }`}
                >
                  <span className="chinese-char text-lg sm:text-xl">{c.char}</span>
                  <span className="text-[8px] sm:text-[9px] font-bold mt-0.5 truncate w-full text-center">{c.name}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Tips */}
          <div className="bg-surface-container-high/30 p-4 sm:p-6 rounded-xl border border-white/20 backdrop-blur-sm">
            <h4 className="text-[10px] sm:text-xs font-bold uppercase tracking-wider text-outline mb-3 sm:mb-4">Practice Tips</h4>
            <ul className="space-y-2 sm:space-y-3 text-[10px] sm:text-xs text-on-surface-variant">
              <li className="flex gap-2">
                <span className="text-primary font-bold flex-shrink-0">•</span>
                <strong>Animate</strong> mode shows you the correct stroke order.
              </li>
              <li className="flex gap-2">
                <span className="text-primary font-bold flex-shrink-0">•</span>
                <strong>Practice</strong> mode lets you draw — hints appear after 2 mistakes.
              </li>
              <li className="flex gap-2">
                <span className="text-primary font-bold flex-shrink-0">•</span>
                Type any Chinese character in the input box to practice it.
              </li>
            </ul>
          </div>
        </div>

        {/* Interactive Drawing Canvas */}
        <div className="lg:col-span-8 relative group order-1 lg:order-2">
          <div className="bg-surface-container-lowest rounded-2xl sm:rounded-3xl aspect-square w-full max-w-[500px] mx-auto shadow-2xl shadow-on-surface/5 relative overflow-hidden flex items-center justify-center border border-surface-variant/30">
            <div className="absolute inset-0 canvas-grid opacity-30"></div>
            <div ref={containerRef} className="relative z-10 flex items-center justify-center w-full h-full" />
          </div>

          {/* Action Bar */}
          <div className="flex justify-center gap-3 mt-6">
            <button
              onClick={handleAnimate}
              className="px-6 py-3 bg-primary text-on-primary rounded-full font-bold text-sm flex items-center gap-2 shadow-lg shadow-primary/20 hover:opacity-90 transition-opacity"
            >
              <span className="material-symbols-outlined text-[18px]">replay</span>
              {mode === 'animate' ? 'Replay' : 'Watch Strokes'}
            </button>
            <button
              onClick={handleQuiz}
              className="px-6 py-3 bg-secondary text-on-secondary rounded-full font-bold text-sm flex items-center gap-2 shadow-lg shadow-secondary/20 hover:opacity-90 transition-opacity"
            >
              <span className="material-symbols-outlined text-[18px]">edit_note</span>
              {mode === 'quiz' ? 'Restart Quiz' : 'Practice Writing'}
            </button>
          </div>

          {/* Stroke Component Breakdown */}
          <div className="grid grid-cols-4 gap-2 sm:gap-4 mt-4 sm:mt-8">
            {[
              { char: '丶', name: 'Diǎn', desc: 'Dot' },
              { char: '一', name: 'Héng', desc: 'Horizontal' },
              { char: '丨', name: 'Shù', desc: 'Vertical' },
              { char: '亅', name: 'Gōu', desc: 'Hook' },
            ].map((stroke) => (
              <button
                key={stroke.name}
                onClick={() => setSelectedChar(stroke.char)}
                className="bg-surface-container-low rounded-lg sm:rounded-xl p-3 sm:p-4 flex flex-col items-center justify-center border border-transparent hover:border-primary/20 transition-all cursor-pointer"
              >
                <span className="chinese-char text-lg sm:text-2xl text-primary">{stroke.char}</span>
                <span className="text-[9px] sm:text-[10px] font-bold mt-1 text-outline">{stroke.name}</span>
                <span className="text-[8px] text-on-surface-variant">{stroke.desc}</span>
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

