import { protectedProcedure, router } from '../trpc';
import { db } from '@/db';
import { reviewLogs, flashcards, userProgress, studySessions, decks } from '@/db/schema';
import { eq, and, desc, asc, sql, count, avg } from 'drizzle-orm';

export const analyticsRouter = router({
  // Heatmap data: daily review counts for the last 365 days
  getHeatmapData: protectedProcedure.query(async ({ ctx }) => {
    const userId = ctx.session.user.id;

    const data = await db
      .select({
        date: studySessions.date,
        cardsReviewed: studySessions.cardsReviewed,
        cardsCorrect: studySessions.cardsCorrect,
      })
      .from(studySessions)
      .where(eq(studySessions.userId, userId))
      .orderBy(asc(studySessions.date))
      .limit(365);

    return data;
  }),

  // Weakest characters: lowest e-factor, most "Again" presses
  getWeakestCharacters: protectedProcedure.query(async ({ ctx }) => {
    const userId = ctx.session.user.id;

    // Characters with lowest e-factor (hardest to remember)
    const weakest = await db
      .select({
        flashcardId: userProgress.flashcardId,
        efactor: userProgress.efactor,
        repetition: userProgress.repetition,
        interval: userProgress.interval,
        character: flashcards.character,
        pinyin: flashcards.pinyin,
        meaning: flashcards.meaning,
      })
      .from(userProgress)
      .innerJoin(flashcards, eq(userProgress.flashcardId, flashcards.id))
      .where(eq(userProgress.userId, userId))
      .orderBy(asc(userProgress.efactor))
      .limit(10);

    // Count "again" presses per character from review logs
    const againCounts = await db
      .select({
        flashcardId: reviewLogs.flashcardId,
        againCount: count(),
      })
      .from(reviewLogs)
      .where(and(eq(reviewLogs.userId, userId), sql`${reviewLogs.quality} < 3`))
      .groupBy(reviewLogs.flashcardId)
      .orderBy(desc(count()))
      .limit(10);

    return { weakest, againCounts };
  }),

  // Session history with trends
  getSessionHistory: protectedProcedure.query(async ({ ctx }) => {
    const userId = ctx.session.user.id;

    const sessions = await db
      .select({
        date: studySessions.date,
        cardsReviewed: studySessions.cardsReviewed,
        cardsCorrect: studySessions.cardsCorrect,
        studyMinutes: studySessions.studyMinutes,
      })
      .from(studySessions)
      .where(eq(studySessions.userId, userId))
      .orderBy(desc(studySessions.date))
      .limit(30);

    return sessions;
  }),

  // Recent review log entries
  getRecentReviews: protectedProcedure.query(async ({ ctx }) => {
    const userId = ctx.session.user.id;

    return await db
      .select({
        quality: reviewLogs.quality,
        responseTimeMs: reviewLogs.responseTimeMs,
        createdAt: reviewLogs.createdAt,
        character: flashcards.character,
        pinyin: flashcards.pinyin,
        meaning: flashcards.meaning,
      })
      .from(reviewLogs)
      .innerJoin(flashcards, eq(reviewLogs.flashcardId, flashcards.id))
      .where(eq(reviewLogs.userId, userId))
      .orderBy(desc(reviewLogs.createdAt))
      .limit(50);
  }),
});

import { z } from 'zod';
import { protectedProcedure, router } from '../trpc';
import { db } from '@/db';
import { userXP, userAchievements, dailyChallenges, reviewLogs, userProgress, flashcards, decks, compoundWords } from '@/db/schema';
import { eq, and, sql, count, desc } from 'drizzle-orm';
import {
  levelFromXP, levelProgress, xpForLevel, getLevelInfo,
  calculateReviewXP, generateDailyChallenges, ACHIEVEMENTS,
  CHALLENGE_TEMPLATES,
} from '@/lib/gamification';

function todayStr() {
  return new Date().toISOString().slice(0, 10);
}

export const gamificationRouter = router({
  // ─── XP & Level ───
  getXPStatus: protectedProcedure.query(async ({ ctx }) => {
    const userId = ctx.session.user.id;
    const rows = await db.select().from(userXP).where(eq(userXP.userId, userId)).limit(1);

    if (rows.length === 0) {
      // Initialize XP record
      await db.insert(userXP).values({ userId, totalXP: 0, level: 1 });
      return {
        totalXP: 0,
        level: 1,
        progress: 0,
        xpToNextLevel: xpForLevel(1),
        levelInfo: getLevelInfo(1),
        currentStreak: 0,
        longestStreak: 0,
      };
    }

    const xp = rows[0];
    const level = levelFromXP(xp.totalXP);
    return {
      totalXP: xp.totalXP,
      level,
      progress: levelProgress(xp.totalXP),
      xpToNextLevel: xpForLevel(level),
      levelInfo: getLevelInfo(level),
      currentStreak: xp.currentStreak,
      longestStreak: xp.longestStreak,
    };
  }),

  /** Award XP and check for level ups + streak. Called after each review. */
  awardXP: protectedProcedure
    .input(z.object({
      xpAmount: z.number().min(0),
      source: z.string().optional(), // 'review' | 'quiz' | 'challenge' | 'achievement'
    }))
    .mutation(async ({ input, ctx }) => {
      const userId = ctx.session.user.id;
      const today = todayStr();

      // Upsert XP record
      const existing = await db.select().from(userXP).where(eq(userXP.userId, userId)).limit(1);

      if (existing.length === 0) {
        const level = levelFromXP(input.xpAmount);
        await db.insert(userXP).values({
          userId,
          totalXP: input.xpAmount,
          level,
          currentStreak: 1,
          longestStreak: 1,
          lastStudyDate: today,
        });
        return { totalXP: input.xpAmount, level, levelUp: level > 1, newAchievements: [] };
      }

      const prev = existing[0];
      const newTotal = prev.totalXP + input.xpAmount;
      const newLevel = levelFromXP(newTotal);
      const levelUp = newLevel > prev.level;

      // Streak logic
      let newStreak = prev.currentStreak;
      let newLongest = prev.longestStreak;

      if (prev.lastStudyDate !== today) {
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const yesterdayStr = yesterday.toISOString().slice(0, 10);

        if (prev.lastStudyDate === yesterdayStr) {
          newStreak = prev.currentStreak + 1;
        } else {
          newStreak = 1; // streak broken
        }
        newLongest = Math.max(newLongest, newStreak);
      }

      await db.update(userXP).set({
        totalXP: newTotal,
        level: newLevel,
        currentStreak: newStreak,
        longestStreak: newLongest,
        lastStudyDate: today,
        updatedAt: new Date(),
      }).where(eq(userXP.userId, userId));

      // Check for new achievements
      const newAchievements = await checkAchievements(userId, newTotal, newStreak);

      return { totalXP: newTotal, level: newLevel, levelUp, newAchievements };
    }),

  // ─── Achievements ───
  getAchievements: protectedProcedure.query(async ({ ctx }) => {
    const userId = ctx.session.user.id;
    const unlocked = await db
      .select({
        achievementKey: userAchievements.achievementKey,
        unlockedAt: userAchievements.unlockedAt,
      })
      .from(userAchievements)
      .where(eq(userAchievements.userId, userId));

    const unlockedKeys = new Set(unlocked.map(u => u.achievementKey));

    return ACHIEVEMENTS.map(a => ({
      ...a,
      unlocked: unlockedKeys.has(a.key),
      unlockedAt: unlocked.find(u => u.achievementKey === a.key)?.unlockedAt ?? null,
    }));
  }),

  getRecentAchievements: protectedProcedure.query(async ({ ctx }) => {
    const userId = ctx.session.user.id;
    return await db
      .select({ achievementKey: userAchievements.achievementKey, unlockedAt: userAchievements.unlockedAt })
      .from(userAchievements)
      .where(eq(userAchievements.userId, userId))
      .orderBy(desc(userAchievements.unlockedAt))
      .limit(5);
  }),

  // ─── Daily Challenges ───
  getDailyChallenges: protectedProcedure.query(async ({ ctx }) => {
    const userId = ctx.session.user.id;
    const today = todayStr();

    const existing = await db
      .select()
      .from(dailyChallenges)
      .where(and(eq(dailyChallenges.userId, userId), eq(dailyChallenges.date, today)));

    if (existing.length > 0) {
      return existing.map(c => {
        const template = CHALLENGE_TEMPLATES.find(t => t.type === c.challengeType);
        return {
          ...c,
          title: template?.title ?? c.challengeType,
          description: (template?.description ?? '').replace('{target}', String(c.targetValue)),
          icon: template?.icon ?? 'task',
        };
      });
    }

    // Generate new daily challenges
    const challenges = generateDailyChallenges();
    const rows = challenges.map(ch => ({
      userId,
      date: today,
      challengeType: ch.type,
      targetValue: ch.target,
      currentValue: 0,
      completed: false,
      xpReward: ch.xpReward,
    }));

    await db.insert(dailyChallenges).values(rows);

    // Re-fetch to get IDs
    return await db
      .select()
      .from(dailyChallenges)
      .where(and(eq(dailyChallenges.userId, userId), eq(dailyChallenges.date, today)))
      .then(rows => rows.map(c => {
        const template = CHALLENGE_TEMPLATES.find(t => t.type === c.challengeType);
        return {
          ...c,
          title: template?.title ?? c.challengeType,
          description: (template?.description ?? '').replace('{target}', String(c.targetValue)),
          icon: template?.icon ?? 'task',
        };
      }));
  }),

  updateChallengeProgress: protectedProcedure
    .input(z.object({
      challengeType: z.string(),
      increment: z.number().default(1),
    }))
    .mutation(async ({ input, ctx }) => {
      const userId = ctx.session.user.id;
      const today = todayStr();

      const challenges = await db
        .select()
        .from(dailyChallenges)
        .where(and(
          eq(dailyChallenges.userId, userId),
          eq(dailyChallenges.date, today),
          eq(dailyChallenges.challengeType, input.challengeType),
        ));

      const completed: { id: number; xpReward: number }[] = [];

      for (const ch of challenges) {
        if (ch.completed) continue;
        const newVal = ch.currentValue + input.increment;
        const isComplete = newVal >= ch.targetValue;
        await db.update(dailyChallenges).set({
          currentValue: newVal,
          completed: isComplete,
        }).where(eq(dailyChallenges.id, ch.id));
        if (isComplete) completed.push({ id: ch.id, xpReward: ch.xpReward });
      }

      return { completed };
    }),

  // ─── Compound Words ───
  getCompoundWords: protectedProcedure
    .input(z.object({ character: z.string() }))
    .query(async ({ input }) => {
      return await db
        .select()
        .from(compoundWords)
        .where(eq(compoundWords.character, input.character))
        .limit(8);
    }),
});

// ─── Achievement Checker (internal) ───
async function checkAchievements(userId: string, totalXP: number, streak: number): Promise<string[]> {
  const existing = await db
    .select({ key: userAchievements.achievementKey })
    .from(userAchievements)
    .where(eq(userAchievements.userId, userId));
  const have = new Set(existing.map(e => e.key));

  // Count total reviews
  const reviewResult = await db
    .select({ total: count() })
    .from(reviewLogs)
    .where(eq(reviewLogs.userId, userId));
  const totalReviews = reviewResult[0]?.total ?? 0;

  // Count mastered cards (rep >= 5, efactor >= 2500)
  const masteredResult = await db
    .select({ total: count() })
    .from(userProgress)
    .where(and(
      eq(userProgress.userId, userId),
      sql`${userProgress.repetition} >= 5`,
      sql`${userProgress.efactor} >= 2500`,
    ));
  const totalMastered = masteredResult[0]?.total ?? 0;

  // Count completed daily challenges
  const challengeResult = await db
    .select({ total: count() })
    .from(dailyChallenges)
    .where(and(
      eq(dailyChallenges.userId, userId),
      eq(dailyChallenges.completed, true),
    ));
  const totalChallenges = challengeResult[0]?.total ?? 0;

  // Count decks
  const deckResult = await db
    .select({ total: count() })
    .from(decks)
    .where(eq(decks.userId, userId));
  const totalDecks = deckResult[0]?.total ?? 0;

  const checks: [string, boolean][] = [
    ['first_review', totalReviews >= 1],
    ['reviews_10', totalReviews >= 10],
    ['reviews_50', totalReviews >= 50],
    ['reviews_100', totalReviews >= 100],
    ['reviews_500', totalReviews >= 500],
    ['reviews_1000', totalReviews >= 1000],
    ['streak_3', streak >= 3],
    ['streak_7', streak >= 7],
    ['streak_30', streak >= 30],
    ['streak_100', streak >= 100],
    ['mastered_10', totalMastered >= 10],
    ['mastered_50', totalMastered >= 50],
    ['daily_x3', totalChallenges >= 3],
    ['daily_x10', totalChallenges >= 10],
    ['deck_creator', totalDecks >= 1],
    ['five_decks', totalDecks >= 5],
  ];

  const newlyUnlocked: string[] = [];

  for (const [key, condition] of checks) {
    if (condition && !have.has(key)) {
      await db.insert(userAchievements).values({ userId, achievementKey: key });
      newlyUnlocked.push(key);
    }
  }

  return newlyUnlocked;
}

import { describe, it, expect } from 'vitest';
import { z } from 'zod';

/**
 * Tests the tRPC router input validation schemas in isolation.
 * These test the Zod schemas used by each endpoint without needing
 * a database or auth context, verifying contract enforcement.
 *
 * Schemas mirror the router files in src/server/routers/*.ts
 */

// ─── Deck Router Schemas ───
const createDeckSchema = z.object({ title: z.string().min(1).max(200), description: z.string().max(1000).optional() });
const deleteDeckSchema = z.object({ id: z.number() });

// ─── Flashcard Router Schemas ───
const getCardsForDeckSchema = z.object({ deckId: z.number() });
const addCardSchema = z.object({
  deckId: z.number(),
  character: z.string().min(1).max(50),
  pinyin: z.string().min(1).max(200),
  meaning: z.string().min(1).max(500),
  strokes: z.number().optional(),
  hskLevel: z.number().optional(),
});
const deleteCardSchema = z.object({ id: z.number() });

// ─── Practice Router Schemas ───
const getDueCardsSchema = z.object({ limit: z.number().min(1).max(100).default(20) });
const submitReviewSchema = z.object({
  progressId: z.number(),
  quality: z.number().min(0).max(5),
});

// ─── Dictionary Router Schemas ───
const searchSchema = z.object({ query: z.string().max(100), hskLevel: z.number().optional() });

// ─── Quiz Router Schemas ───
const quizSchema = z.object({ count: z.number().min(1).max(50).default(10), hskLevel: z.number().optional() });
const submitQuizAnswerSchema = z.object({
  flashcardId: z.number(),
  selectedAnswer: z.string(),
});

// ─── Import Router Schemas ───
const importCardsSchema = z.object({
  deckId: z.number(),
  cards: z.array(z.object({
    character: z.string().min(1).max(50),
    pinyin: z.string().min(1).max(200),
    meaning: z.string().min(1).max(500),
    strokes: z.number().optional(),
    hskLevel: z.number().optional(),
  })).max(500),
});

describe('tRPC Router — Input Schema Validation', () => {

  describe('createDeck', () => {
    it('accepts valid title + description', () => {
      expect(createDeckSchema.parse({ title: 'HSK 1', description: 'Beginner' }))
        .toEqual({ title: 'HSK 1', description: 'Beginner' });
    });

    it('accepts title without description', () => {
      expect(createDeckSchema.parse({ title: 'My Deck' }))
        .toEqual({ title: 'My Deck' });
    });

    it('rejects empty title', () => {
      expect(() => createDeckSchema.parse({ title: '' })).toThrow();
    });

    it('rejects missing title', () => {
      expect(() => createDeckSchema.parse({})).toThrow();
    });

    it('rejects title exceeding 200 characters', () => {
      expect(() => createDeckSchema.parse({ title: 'a'.repeat(201) })).toThrow();
    });

    it('rejects description exceeding 1000 characters', () => {
      expect(() => createDeckSchema.parse({ title: 'ok', description: 'x'.repeat(1001) })).toThrow();
    });
  });

  describe('deleteDeck', () => {
    it('accepts valid id', () => {
      expect(deleteDeckSchema.parse({ id: 42 })).toEqual({ id: 42 });
    });

    it('rejects string id', () => {
      expect(() => deleteDeckSchema.parse({ id: 'abc' })).toThrow();
    });

    it('rejects missing id', () => {
      expect(() => deleteDeckSchema.parse({})).toThrow();
    });
  });

  describe('addCard', () => {
    it('accepts valid card with all fields', () => {
      const card = { deckId: 1, character: '学', pinyin: 'xué', meaning: 'study', strokes: 8, hskLevel: 1 };
      expect(addCardSchema.parse(card)).toEqual(card);
    });

    it('accepts card without optional fields', () => {
      const card = { deckId: 1, character: '学', pinyin: 'xué', meaning: 'study' };
      expect(addCardSchema.parse(card)).toEqual(card);
    });

    it('rejects empty character', () => {
      expect(() => addCardSchema.parse({ deckId: 1, character: '', pinyin: 'a', meaning: 'b' })).toThrow();
    });

    it('rejects empty pinyin', () => {
      expect(() => addCardSchema.parse({ deckId: 1, character: '学', pinyin: '', meaning: 'b' })).toThrow();
    });

    it('rejects empty meaning', () => {
      expect(() => addCardSchema.parse({ deckId: 1, character: '学', pinyin: 'x', meaning: '' })).toThrow();
    });

    it('rejects missing deckId', () => {
      expect(() => addCardSchema.parse({ character: '学', pinyin: 'x', meaning: 'y' })).toThrow();
    });

    it('rejects character exceeding 50 chars', () => {
      expect(() => addCardSchema.parse({ deckId: 1, character: '字'.repeat(51), pinyin: 'x', meaning: 'y' })).toThrow();
    });

    it('rejects meaning exceeding 500 chars', () => {
      expect(() => addCardSchema.parse({ deckId: 1, character: '字', pinyin: 'x', meaning: 'y'.repeat(501) })).toThrow();
    });
  });

  describe('submitReview', () => {
