    });

    it('accepts custom count and hskLevel', () => {
      expect(quizSchema.parse({ count: 20, hskLevel: 3 }))
        .toEqual({ count: 20, hskLevel: 3 });
    });

    it('rejects count below 1', () => {
      expect(() => quizSchema.parse({ count: 0 })).toThrow();
